INSERT INTO recipes (title, slug, description, quick_summary, cuisine, difficulty, prep_time, cook_time, total_time, servings, calories, protein, carbs, fat, fiber, ingredients, steps, substitutions, common_mistakes, tags, dietary, category, source) VALUES ('Garlic Butter Shrimp Pasta', 'garlic-butter-shrimp-pasta', 'A luxuriously rich and satisfying pasta dish featuring plump, golden-seared shrimp tossed in a velvety garlic butter sauce with a hint of white wine and fresh lemon. This weeknight hero comes together in just 15 but tastes like something straight from a coastal Italian trattoria. Every forkful delivers tender linguine coated in silky, aromatic butter sauce with juicy shrimp that practically melt in your mouth.', 'Juicy seared shrimp and linguine bathed in a golden garlic butter sauce with lemon and parsley — restaurant-quality in 15 flat.', 'Italian-American', 'Easy', 5, 10, 15, 4, 520, 38, 52, 18, 3, '[{"amount":"400","unit":"g","item":"linguine pasta","group":"Pasta"},{"amount":"500","unit":"g","item":"large raw shrimp, peeled and deveined","group":"Protein"},{"amount":"6","unit":"cloves","item":"garlic, minced","group":"Aromatics"},{"amount":"4","unit":"tbsp","item":"unsalted butter","group":"Sauce"},{"amount":"2","unit":"tbsp","item":"extra virgin olive oil","group":"Sauce"},{"amount":"80","unit":"ml","item":"dry white wine","group":"Sauce"},{"amount":"1","unit":"whole","item":"lemon, zested and juiced","group":"Sauce"},{"amount":"1","unit":"tsp","item":"red pepper flakes","group":"Aromatics"},{"amount":"1","unit":"tsp","item":"sea salt","group":"Seasoning"},{"amount":"0.5","unit":"tsp","item":"black pepper, freshly ground","group":"Seasoning"},{"amount":"30","unit":"g","item":"fresh flat-leaf parsley, roughly chopped","group":"Garnish"},{"amount":"40","unit":"g","item":"Parmesan cheese, freshly grated","group":"Garnish"},{"amount":"120","unit":"ml","item":"reserved pasta cooking water","group":"Sauce"}]', '[{"title":"Boil the Pasta","text":"Bring a large pot of heavily salted water to a rolling boil. Add the linguine and cook according to package directions until just al dente, about 8 to 9. Before draining, scoop out approximately 120ml of starchy pasta water and set it aside. Drain the pasta and do not rinse it.","timer":540},{"title":"Season the Shrimp","text":"While the pasta cooks, pat the shrimp completely dry with paper towels — this is critical for a good sear. Season generously on both sides with half the sea salt and all of the black pepper. Dry shrimp means golden shrimp, so take an extra moment here.","timer":60},{"title":"Sear the Shrimp","text":"Heat a large wide skillet over high heat until very hot. Add the olive oil and swirl to coat. Add the shrimp in a single layer — do not crowd the pan. Sear undisturbed for 90 seconds until the underside is pink and slightly golden, then flip each shrimp and cook for another 60 seconds. Transfer to a plate immediately. They will finish cooking when returned to the sauce.","timer":150},{"title":"Build the Garlic Butter Sauce","text":"Reduce the heat to medium. Add 2 tablespoons of the butter to the same skillet. Once melted and foamy, add the minced garlic and red pepper flakes. Stir constantly for 60 seconds until the garlic is fragrant and just turning golden — watch it closely as it can burn quickly. Pour in the white wine and let it bubble and reduce by half, about 90 seconds, scraping up any browned bits from the bottom of the pan.","timer":150},{"title":"Bring It All Together","text":"Add the drained linguine directly into the skillet along with the remaining 2 tablespoons of butter, lemon zest, and lemon juice. Toss vigorously with tongs, splashing in the reserved pasta water a little at a time until a glossy, emulsified sauce coats every strand of pasta. Return the seared shrimp to the pan and toss everything together for 60 seconds over medium heat until the shrimp are warmed through and perfectly glazed.","timer":60},{"title":"Plate and Garnish","text":"Divide the pasta among four warm bowls, making sure each portion gets a generous scattering of shrimp. Top with freshly chopped parsley, a shower of grated Parmesan, and an optional extra squeeze of lemon. Serve immediately while steaming hot.","timer":60}]', '[{"original":"dry white wine","swap":"low-sodium chicken broth with an extra squeeze of lemon for a non-alcoholic version"},{"original":"linguine","swap":"spaghetti, fettuccine, or gluten-free pasta"},{"original":"large raw shrimp","swap":"sea scallops or chunks of firm white fish like cod"},{"original":"unsalted butter","swap":"vegan butter or additional olive oil for a dairy-free option"},{"original":"Parmesan cheese","swap":"nutritional yeast for a dairy-free umami kick"},{"original":"fresh parsley","swap":"fresh basil or chives"}]', '["Not patting the shrimp dry before searing, which causes them to steam instead of develop a golden crust","Overcooking the shrimp — they only need about 2 to 3 total and will become rubbery if left too long","Burning the garlic by using heat that is too high or leaving it unattended — it should be golden, not brown","Forgetting to reserve pasta water before draining, which is the secret to a silky emulsified sauce","Rinsing the pasta after draining, which washes away the starch that helps the sauce cling","Crowding the shrimp in the pan — cook in batches if your skillet is not large enough"]', '["quick dinner","weeknight meal","shrimp","pasta","garlic butter","15","seafood","easy","date night","high protein"]', '["high-protein"]', 'quick', 'ai');
INSERT INTO recipes (title, slug, description, quick_summary, cuisine, difficulty, prep_time, cook_time, total_time, servings, calories, protein, carbs, fat, fiber, ingredients, steps, substitutions, common_mistakes, tags, dietary, category, source) VALUES ('Golden Turmeric Quinoa Buddha Bowl with Creamy Tahini Dressing', 'golden-turmeric-quinoa-buddha-bowl-tahini-dressing', 'A vibrant, nourishing Buddha bowl packed with golden turmeric quinoa, crispy roasted chickpeas, rainbow vegetables, and drizzled with a luscious lemon-tahini dressing. This powerhouse meal is as beautiful as it is satisfying, delivering plant-based protein in every single bite. Perfect for weekly meal prep, this bowl keeps you energized, focused, and genuinely excited about eating your greens.', 'Vibrant vegan Buddha bowl with turmeric quinoa, crispy chickpeas, roasted veggies, and creamy tahini dressing — meal-prep friendly and packed with plant protein.', 'Modern Plant-Based', 'Easy', 20, 35, 55, 4, 582, 24, 68, 24, 14, '[{"amount":"1.5","unit":"cups","item":"dry quinoa, rinsed","group":"Turmeric Quinoa"},{"amount":"3","unit":"cups","item":"vegetable broth","group":"Turmeric Quinoa"},{"amount":"1","unit":"tsp","item":"ground turmeric","group":"Turmeric Quinoa"},{"amount":"0.5","unit":"tsp","item":"garlic powder","group":"Turmeric Quinoa"},{"amount":"0.5","unit":"tsp","item":"fine sea salt","group":"Turmeric Quinoa"},{"amount":"1","unit":"tbsp","item":"olive oil","group":"Turmeric Quinoa"},{"amount":"2","unit":"cans","item":"chickpeas (15 oz each), drained and rinsed","group":"Crispy Chickpeas"},{"amount":"2","unit":"tbsp","item":"olive oil","group":"Crispy Chickpeas"},{"amount":"1","unit":"tsp","item":"smoked paprika","group":"Crispy Chickpeas"},{"amount":"1","unit":"tsp","item":"ground cumin","group":"Crispy Chickpeas"},{"amount":"0.5","unit":"tsp","item":"garlic powder","group":"Crispy Chickpeas"},{"amount":"0.5","unit":"tsp","item":"fine sea salt","group":"Crispy Chickpeas"},{"amount":"0.25","unit":"tsp","item":"cayenne pepper","group":"Crispy Chickpeas"},{"amount":"2","unit":"medium","item":"sweet potatoes, peeled and cubed into 1-inch pieces","group":"Roasted Vegetables"},{"amount":"2","unit":"medium","item":"red bell peppers, sliced","group":"Roasted Vegetables"},{"amount":"1","unit":"medium","item":"zucchini, sliced into half-moons","group":"Roasted Vegetables"},{"amount":"2","unit":"tbsp","item":"olive oil","group":"Roasted Vegetables"},{"amount":"1","unit":"tsp","item":"Italian seasoning","group":"Roasted Vegetables"},{"amount":"0.5","unit":"tsp","item":"fine sea salt","group":"Roasted Vegetables"},{"amount":"0.25","unit":"tsp","item":"black pepper","group":"Roasted Vegetables"},{"amount":"4","unit":"cups","item":"baby spinach or mixed greens","group":"Bowl Base"},{"amount":"1","unit":"cup","item":"shredded purple cabbage","group":"Bowl Base"},{"amount":"1","unit":"cup","item":"cherry tomatoes, halved","group":"Bowl Base"},{"amount":"1","unit":"medium","item":"avocado, sliced","group":"Bowl Base"},{"amount":"0.5","unit":"cup","item":"well-stirred tahini","group":"Tahini Dressing"},{"amount":"3","unit":"tbsp","item":"fresh lemon juice","group":"Tahini Dressing"},{"amount":"1","unit":"clove","item":"garlic, minced or grated","group":"Tahini Dressing"},{"amount":"2","unit":"tsp","item":"pure maple syrup","group":"Tahini Dressing"},{"amount":"0.5","unit":"tsp","item":"fine sea salt","group":"Tahini Dressing"},{"amount":"6","unit":"tbsp","item":"warm water, plus more to thin","group":"Tahini Dressing"},{"amount":"2","unit":"tbsp","item":"hemp seeds","group":"Toppings"},{"amount":"2","unit":"tbsp","item":"toasted sesame seeds","group":"Toppings"},{"amount":"4","unit":"sprigs","item":"fresh parsley or cilantro","group":"Toppings"},{"amount":"1","unit":"pinch","item":"red chili flakes","group":"Toppings"}]', '[{"title":"Preheat and Prep","text":"Preheat your oven to 425°F (220°C). Line two large rimmed baking sheets with parchment paper. Pat your drained chickpeas completely dry using a clean kitchen towel or paper towels — this is the secret to maximum crispiness. Set aside. Cube your sweet potatoes, slice the bell peppers, and cut the zucchini so everything is ready to go.","timer":0},{"title":"Season and Roast the Chickpeas","text":"Spread the dried chickpeas onto one prepared baking sheet in a single layer. Drizzle with 2 tablespoons olive oil, then sprinkle over the smoked paprika, cumin, garlic powder, salt, and cayenne. Toss well to coat every chickpea evenly. Spread them back into a single layer with space between each one. Roast on the top rack of the oven for 30 to 35, shaking the pan halfway through, until deeply golden, crispy, and irresistible.","timer":2100},{"title":"Roast the Vegetables","text":"On the second baking sheet, spread the cubed sweet potatoes, sliced bell peppers, and zucchini. Drizzle with 2 tablespoons olive oil, then sprinkle with Italian seasoning, salt, and black pepper. Toss to coat and spread into an even single layer. Roast on the lower rack alongside the chickpeas for 25 to 30, flipping once halfway through, until the sweet potatoes are fork-tender and the edges are caramelized.","timer":1800},{"title":"Cook the Turmeric Quinoa","text":"While the oven does its work, combine the rinsed quinoa, vegetable broth, turmeric, garlic powder, salt, and olive oil in a medium saucepan over medium-high heat. Bring to a full boil, then reduce the heat to low, cover with a tight-fitting lid, and simmer for 15. Remove from heat and let it steam, covered, for 5 additional minutes. Fluff with a fork — you should see beautiful golden quinoa with little tails curled around each grain.","timer":1200},{"title":"Make the Tahini Dressing","text":"In a small bowl or jar, whisk together the tahini, fresh lemon juice, minced garlic, maple syrup, and salt until combined. The mixture will seize up and look thick — that is completely normal. Add the warm water one tablespoon at a time, whisking vigorously after each addition, until you reach a smooth, pourable, creamy consistency similar to a thick salad dressing. Taste and adjust lemon, salt, or maple syrup to your preference. If prepping ahead, store in a sealed jar and stir before using.","timer":0},{"title":"Assemble Your Buddha Bowls","text":"Divide the baby spinach or mixed greens evenly among four wide bowls as your base. Add a generous scoop of turmeric quinoa to one section of each bowl. Arrange the roasted sweet potatoes, peppers, and zucchini in another section. Add a pile of crispy chickpeas. Fan out the sliced avocado, pile on the shredded purple cabbage, and scatter the cherry tomatoes. Drizzle everything generously with the creamy tahini dressing, then finish with hemp seeds, toasted sesame seeds, a sprig of fresh parsley or cilantro, and a pinch of red chili flakes.","timer":0},{"title":"Serve or Store for Meal Prep","text":"Serve immediately for maximum chickpea crispiness. For meal prep, store components separately in airtight containers in the refrigerator for up to 4 days. Keep the avocado and tahini dressing separate until ready to eat. Store crispy chickpeas in a loosely covered container at room temperature to maintain their crunch. When ready to eat, reheat the quinoa and roasted vegetables, assemble the bowl fresh, and drizzle with dressing.","timer":0}]', '[{"original":"quinoa","swap":"brown rice, farro, or cauliflower rice for a lower-carb option"},{"original":"chickpeas","swap":"white beans, edamame, or baked tofu cubes for protein variety"},{"original":"sweet potatoes","swap":"butternut squash, beets, or parsnips"},{"original":"tahini","swap":"sunflower seed butter for a nut-free alternative with a similar creamy richness"},{"original":"maple syrup","swap":"agave nectar or a medjool date blended into the dressing"},{"original":"baby spinach","swap":"kale (massaged with a little olive oil and lemon), arugula, or romaine"},{"original":"hemp seeds","swap":"pumpkin seeds or sunflower seeds for added crunch and protein"},{"original":"lemon juice","swap":"apple cider vinegar for a slightly different tangy note"}]', '["Not drying the chickpeas thoroughly before roasting — excess moisture creates steamed, soft chickpeas instead of crispy ones","Overcrowding the baking sheet with vegetables or chickpeas, which causes steaming instead of roasting and results in soggy textures","Skipping the 5-minute resting step after cooking quinoa — this is essential for fluffy, separated grains rather than a clumped, mushy result","Adding cold water instead of warm water to the tahini dressing — warm water emulsifies the tahini far more smoothly","Under-seasoning the roasted vegetables — taste and season generously at each step for bold, satisfying flavors","Slicing the avocado too early if meal prepping — always slice fresh right before serving to prevent browning","Storing crispy chickpeas in a sealed airtight container, which traps steam and makes them soft — use a loosely covered bowl at room temperature instead","Pouring dressing directly onto greens when meal prepping — always store it separately to prevent wilting"]', '["buddha bowl","vegan","meal prep","high protein","tahini","quinoa","chickpeas","roasted vegetables","healthy lunch","plant based","turmeric","dairy free","gluten free","weekly prep","avocado","colorful bowl","anti inflammatory","fiber rich"]', '["vegan","plant-based","high-protein","gluten-free","dairy-free","nut-free"]', 'meal-prep', 'ai');
INSERT INTO recipes (title, slug, description, quick_summary, cuisine, difficulty, prep_time, cook_time, total_time, servings, calories, protein, carbs, fat, fiber, ingredients, steps, substitutions, common_mistakes, tags, dietary, category, source) VALUES ('Classic Chicken Tikka Masala', 'classic-chicken-tikka-masala', 'A soul-warming Indian-British classic featuring tender charred chicken pieces nestled in a velvety, spiced tomato cream sauce. This deeply aromatic dish layers complex spices with a luscious richness that makes it utterly irresistible. Perfect over fluffy basmati rice, every bite delivers smoky, tangy, and creamy notes in perfect harmony.', 'Juicy marinated chicken meets a rich, smoky tomato-cream sauce loaded with warming spices. A guaranteed crowd-pleaser that tastes like it came straight from your favorite Indian restaurant.', 'Indian-British', 'Medium', 30 (plus 4 marinating), 45, 5 15, 4, 520, 48, 18, 28, 4, '[{"amount":"800","unit":"g","item":"boneless skinless chicken thighs, cut into 2-inch pieces","group":"Chicken & Marinade"},{"amount":"1","unit":"cup","item":"full-fat plain yogurt","group":"Chicken & Marinade"},{"amount":"2","unit":"tbsp","item":"fresh lemon juice","group":"Chicken & Marinade"},{"amount":"4","unit":"cloves","item":"garlic, minced","group":"Chicken & Marinade"},{"amount":"1","unit":"tbsp","item":"fresh ginger, grated","group":"Chicken & Marinade"},{"amount":"2","unit":"tsp","item":"ground cumin","group":"Chicken & Marinade"},{"amount":"2","unit":"tsp","item":"ground coriander","group":"Chicken & Marinade"},{"amount":"1.5","unit":"tsp","item":"Kashmiri chili powder or sweet paprika","group":"Chicken & Marinade"},{"amount":"1","unit":"tsp","item":"garam masala","group":"Chicken & Marinade"},{"amount":"1","unit":"tsp","item":"turmeric","group":"Chicken & Marinade"},{"amount":"1","unit":"tsp","item":"fine sea salt","group":"Chicken & Marinade"},{"amount":"2","unit":"tbsp","item":"neutral oil (such as avocado or vegetable oil)","group":"Masala Sauce"},{"amount":"2","unit":"tbsp","item":"unsalted butter","group":"Masala Sauce"},{"amount":"1","unit":"large","item":"yellow onion, finely diced","group":"Masala Sauce"},{"amount":"5","unit":"cloves","item":"garlic, minced","group":"Masala Sauce"},{"amount":"1.5","unit":"tbsp","item":"fresh ginger, grated","group":"Masala Sauce"},{"amount":"2","unit":"tsp","item":"ground cumin","group":"Masala Sauce"},{"amount":"2","unit":"tsp","item":"ground coriander","group":"Masala Sauce"},{"amount":"2","unit":"tsp","item":"Kashmiri chili powder or sweet paprika","group":"Masala Sauce"},{"amount":"1.5","unit":"tsp","item":"garam masala","group":"Masala Sauce"},{"amount":"1","unit":"tsp","item":"turmeric","group":"Masala Sauce"},{"amount":"1","unit":"tsp","item":"smoked paprika","group":"Masala Sauce"},{"amount":"2","unit":"tbsp","item":"tomato paste","group":"Masala Sauce"},{"amount":"1","unit":"can (400g)","item":"crushed San Marzano tomatoes","group":"Masala Sauce"},{"amount":"1","unit":"cup","item":"heavy cream","group":"Masala Sauce"},{"amount":"0.5","unit":"cup","item":"chicken stock (gluten-free certified)","group":"Masala Sauce"},{"amount":"1","unit":"tsp","item":"fine sea salt, or to taste","group":"Masala Sauce"},{"amount":"1","unit":"tsp","item":"sugar","group":"Masala Sauce"},{"amount":"2","unit":"tbsp","item":"fresh cilantro, roughly chopped","group":"To Serve"},{"amount":"1","unit":"tbsp","item":"heavy cream, for drizzling","group":"To Serve"},{"amount":"2","unit":"cups","item":"cooked basmati rice","group":"To Serve"}]', '[{"title":"Marinate the Chicken","text":"In a large bowl, whisk together the yogurt, lemon juice, minced garlic, grated ginger, cumin, coriander, Kashmiri chili powder, garam masala, turmeric, and salt. Add the chicken pieces and toss thoroughly until every piece is well coated. Cover the bowl with plastic wrap and refrigerate for a minimum of 4, or overnight for the deepest flavor. The longer it marinates, the more tender and flavorful your chicken will be.","timer":14400},{"title":"Broil the Chicken","text":"Remove the chicken from the refrigerator 20 before cooking to take the chill off. Preheat your oven broiler to high (or a grill pan over high heat). Thread the chicken onto metal skewers or arrange in a single layer on a foil-lined baking sheet lightly greased with oil. Broil 6 inches from the heat for 10 to 12, turning halfway through, until the chicken is deeply charred in spots and cooked through with an internal temperature of 165°F (74°C). Set aside — those charred bits are pure flavor gold.","timer":720},{"title":"Build the Aromatic Base","text":"Heat the oil and butter together in a large, heavy-bottomed pot or Dutch oven over medium heat until the butter is melted and foaming. Add the diced onion and cook, stirring frequently, for 12 to 15 until deeply golden and starting to caramelize — do not rush this step. Add the garlic and ginger and cook for another 2, stirring constantly, until fragrant and the raw smell disappears.","timer":840},{"title":"Bloom the Spices","text":"Add the tomato paste to the pot and stir it into the onion mixture. Cook for 3, stirring frequently, until the tomato paste deepens in color to a brick red. Add the cumin, coriander, Kashmiri chili powder, garam masala, turmeric, and smoked paprika all at once. Stir vigorously for 60 to 90 seconds until the spices coat everything and the mixture becomes very fragrant. Blooming the spices in fat is essential for developing the deep, complex flavor of the sauce.","timer":180},{"title":"Simmer the Tomato Sauce","text":"Pour in the crushed tomatoes and chicken stock, scraping up any browned bits from the bottom of the pot. Add the salt and sugar, stir to combine, and bring to a gentle boil. Reduce heat to low, partially cover, and simmer for 15, stirring occasionally, until the sauce has thickened and the oil starts to separate slightly on the surface — this is a sign the sauce is properly cooked.","timer":900},{"title":"Blend for Silkiness","text":"Using an immersion blender directly in the pot, blend the sauce until completely smooth and velvety. Alternatively, carefully transfer in batches to a countertop blender (allowing steam to escape). Return the blended sauce to the pot over low heat. This step transforms the sauce from rustic to restaurant-quality silky.","timer":120},{"title":"Finish with Cream and Chicken","text":"Pour in the heavy cream and stir gently to combine. Add the broiled chicken pieces, including any resting juices from the pan — those juices add incredible flavor. Stir everything together and simmer over low heat for 8 to 10 until the chicken is heated through, tender, and the sauce clings to each piece beautifully. Taste and adjust seasoning with salt or a pinch more garam masala if desired.","timer":600},{"title":"Plate and Serve","text":"Ladle the chicken tikka masala over steamed basmati rice. Finish with a swirl of heavy cream for that signature restaurant look, and scatter fresh cilantro generously over the top. Serve immediately while piping hot. Pair with gluten-free naan if desired, and prepare for an absolute silence at the dinner table — the best kind of compliment.","timer":0}]', '[{"original":"Heavy cream","swap":"Full-fat coconut cream for a dairy-free and equally rich result"},{"original":"Plain yogurt in marinade","swap":"Coconut yogurt for a dairy-free, slightly sweeter marinade"},{"original":"Chicken thighs","swap":"Chicken breast for lower fat, but reduce broiling time by 2 to avoid dryness"},{"original":"Butter","swap":"Ghee for a more authentic, nuttier flavor, or use vegan butter to keep it dairy-free"},{"original":"Kashmiri chili powder","swap":"Equal parts sweet paprika and a pinch of cayenne for a similar color and mild heat"},{"original":"Fresh ginger","swap":"Half the amount of ground ginger in a pinch, though fresh is strongly preferred"},{"original":"Crushed San Marzano tomatoes","swap":"4 ripe Roma tomatoes, blanched and blended, for a fresh and slightly lighter sauce"}]', '["Skipping or shortening the marinating time — less than 4 results in less tender and flavorful chicken","Not caramelizing the onions long enough, which robs the sauce of its foundational sweetness and depth","Burning the spices during blooming by using heat that is too high — they should sizzle gently, not smoke","Adding cream to a sauce that is still boiling vigorously, which can cause it to break and become grainy","Using low-fat yogurt in the marinade, which lacks the fat needed to protect the chicken from drying out during broiling","Skipping the blending step and leaving the sauce chunky, missing the signature velvety restaurant-style texture","Not patting the chicken dry before broiling — excess marinade moisture steams instead of chars, losing that essential tikka smokiness","Under-seasoning the sauce — always taste and adjust salt and spice levels before adding the chicken back in"]', '["chicken tikka masala","Indian","curry","comfort food","weeknight dinner","meal prep","spicy","creamy","tomato","marinated chicken","restaurant-style","one-pot","date night","batch cooking"]', '["high-protein","gluten-free"]', 'comfort', 'ai');
INSERT INTO recipes (title, slug, description, quick_summary, cuisine, difficulty, prep_time, cook_time, total_time, servings, calories, protein, carbs, fat, fiber, ingredients, steps, substitutions, common_mistakes, tags, dietary, category, source) VALUES ('3-Ingredient Banana Pancakes', '3-ingredient-banana-pancakes', 'These impossibly simple banana pancakes require nothing but ripe bananas, eggs, and a pinch of baking powder — yet somehow deliver fluffy, naturally sweet stacks that taste like you actually tried. Perfect for mornings when your wallet is crying but your stomach is screaming.', 'Mash, mix, and flip your way to golden banana pancakes with just 3 ingredients in under 15.', 'American', 'Easy', 5, 10, 15, 2, 180, 9, 28, 6, 2, '[{"amount":"2","unit":"large","item":"very ripe bananas (the blacker the better)","group":"batter"},{"amount":"2","unit":"whole","item":"eggs","group":"batter"},{"amount":"0.5","unit":"teaspoon","item":"baking powder","group":"batter"},{"amount":"1","unit":"teaspoon","item":"butter or cooking spray (for the pan)","group":"cooking"}]', '[{"title":"Mash the Bananas","text":"Peel both bananas and place them in a medium bowl. Mash aggressively with a fork until you get a smooth, mostly lump-free paste. The riper and spottier the bananas, the sweeter and easier to mash — this is the one time a sad, forgotten banana is your best friend.","timer":60},{"title":"Mix the Batter","text":"Crack both eggs directly into the mashed banana. Add the baking powder. Whisk everything together vigorously for about 30 seconds until fully combined and slightly airy. The batter will be thinner and looser than traditional pancake batter — that is completely normal, do not panic.","timer":45},{"title":"Heat the Pan","text":"Place a non-stick skillet or frying pan over medium-low heat. Add a small knob of butter or a quick spritz of cooking spray and let it melt and coat the surface evenly. Medium-low is key here — these pancakes burn faster than regular ones because of the natural banana sugars, so resist the urge to crank the heat.","timer":90},{"title":"Cook the Pancakes","text":"Pour roughly 3 tablespoons of batter per pancake into the pan, forming small rounds about 3 inches wide. Cook for 2 to 3 until the edges look set and the tops develop small bubbles and appear mostly dry. These are more delicate than flour pancakes so keep them small — big ones fall apart on the flip.","timer":150},{"title":"Flip and Finish","text":"Carefully slide a thin spatula fully under each pancake and flip in one confident motion — hesitation is the enemy. Cook for another 1 to 2 on the second side until golden brown. Transfer to a plate and repeat with remaining batter, adding a tiny bit more butter between batches if needed.","timer":90},{"title":"Serve Immediately","text":"Stack them up and serve right away while warm. They are fantastic on their own, but a drizzle of honey, a handful of whatever berries you have, or even just a dusting of cinnamon from the back of your spice cabinet takes them to another level entirely.","timer":0}]', '[{"original":"eggs","swap":"2 tablespoons of peanut butter blended with the banana for a vegan version — texture will be denser but still delicious"},{"original":"butter for the pan","swap":"any neutral oil like vegetable or canola oil works perfectly fine"},{"original":"baking powder","swap":"a tiny pinch of baking soda if that is all you have, though the lift will be slightly less dramatic"}]', '["Cooking on heat that is too high — banana sugars caramelize and burn quickly, always use medium-low","Making the pancakes too large — small 3-inch pancakes are far easier to flip without breaking","Using underripe yellow bananas — they do not mash smoothly and the pancakes will lack sweetness and flavor","Flipping too early before the edges are fully set — patience on the first side prevents crumbling","Expecting them to taste exactly like flour pancakes — they are softer, eggier, and naturally sweeter, which is a feature not a flaw"]', '["banana","pancakes","breakfast","3-ingredient","budget","quick","college","no flour","gluten-free friendly","easy"]', '["vegetarian","gluten-free","dairy-free optional","nut-free"]', 'budget', 'ai');
INSERT INTO recipes (title, slug, description, quick_summary, cuisine, difficulty, prep_time, cook_time, total_time, servings, calories, protein, carbs, fat, fiber, ingredients, steps, substitutions, common_mistakes, tags, dietary, category, source) VALUES ('Creamy Keto Cauliflower Mac and Cheese', 'creamy-keto-cauliflower-mac-and-cheese', 'This indulgent keto cauliflower mac and cheese delivers all the comfort of the classic dish without the carbs. Tender cauliflower florets are smothered in a rich, velvety three-cheese sauce made with sharp cheddar, gruyère, and cream cheese, then finished under the broiler for a golden, bubbly crust. It is the ultimate low-carb comfort food that will satisfy even the most devoted mac and cheese lover.', 'Tender cauliflower florets bathed in a luxurious three-cheese sauce, broiled to golden perfection for the ultimate keto comfort meal.', 'American', 'Easy', 15, 25, 40, 4, 420, 22, 9, 34, 3, '[{"amount":"1","unit":"large head","item":"cauliflower, cut into small florets","group":"Cauliflower"},{"amount":"1","unit":"tablespoon","item":"olive oil","group":"Cauliflower"},{"amount":"1","unit":"teaspoon","item":"salt","group":"Cauliflower"},{"amount":"4","unit":"oz","item":"full-fat cream cheese, softened","group":"Cheese Sauce"},{"amount":"1","unit":"cup","item":"heavy whipping cream","group":"Cheese Sauce"},{"amount":"1.5","unit":"cups","item":"sharp cheddar cheese, freshly shredded","group":"Cheese Sauce"},{"amount":"0.5","unit":"cup","item":"gruyère cheese, freshly shredded","group":"Cheese Sauce"},{"amount":"2","unit":"cloves","item":"garlic, minced","group":"Cheese Sauce"},{"amount":"1","unit":"teaspoon","item":"Dijon mustard","group":"Cheese Sauce"},{"amount":"0.5","unit":"teaspoon","item":"smoked paprika","group":"Cheese Sauce"},{"amount":"0.25","unit":"teaspoon","item":"onion powder","group":"Cheese Sauce"},{"amount":"0.25","unit":"teaspoon","item":"ground black pepper","group":"Cheese Sauce"},{"amount":"0.25","unit":"teaspoon","item":"cayenne pepper","group":"Cheese Sauce"},{"amount":"2","unit":"tablespoons","item":"unsalted butter","group":"Cheese Sauce"},{"amount":"0.5","unit":"cup","item":"sharp cheddar cheese, shredded, for topping","group":"Topping"},{"amount":"2","unit":"tablespoons","item":"fresh chives, chopped","group":"Topping"},{"amount":"4","unit":"slices","item":"bacon, cooked and crumbled","group":"Topping"}]', '[{"title":"Preheat and Prep","text":"Preheat your oven to 400°F (200°C). Bring a large pot of salted water to a boil. Line a baking sheet with paper towels and set aside.","timer":0},{"title":"Blanch the Cauliflower","text":"Add the cauliflower florets to the boiling water and cook for exactly 4. You want them just tender but still holding their shape — they will continue cooking in the oven. Drain immediately and spread on the paper towel-lined baking sheet. Pat completely dry with more paper towels. Drying is critical to avoid a watery sauce.","timer":240},{"title":"Roast the Cauliflower","text":"Transfer the dried cauliflower florets to a large baking dish or cast iron skillet. Drizzle with olive oil, season with salt, and toss to coat. Roast in the preheated oven for 10 until the edges just begin to turn golden. This step adds depth of flavor and removes excess moisture.","timer":600},{"title":"Build the Cheese Sauce","text":"While the cauliflower roasts, melt the butter in a medium saucepan over medium heat. Add the minced garlic and sauté for 1 minute until fragrant. Add the cream cheese and stir constantly until completely melted and smooth, about 2. Pour in the heavy whipping cream and whisk until fully combined and beginning to simmer gently.","timer":180},{"title":"Add the Cheeses and Seasonings","text":"Reduce the heat to low. Add the shredded cheddar and gruyère one handful at a time, stirring each addition until fully melted before adding the next. Stir in the Dijon mustard, smoked paprika, onion powder, black pepper, and cayenne. Taste and adjust seasoning. The sauce should be thick, smooth, and glossy.","timer":300},{"title":"Combine and Top","text":"Remove the roasted cauliflower from the oven and switch the oven to broil on high. Pour the cheese sauce evenly over the cauliflower, gently folding to coat every floret. Sprinkle the reserved half cup of shredded cheddar evenly over the top along with the crumbled bacon.","timer":0},{"title":"Broil to Finish","text":"Place the dish under the broiler for 3 to 4, watching closely, until the cheese on top is melted, bubbly, and has beautiful golden-brown spots. Remove from the oven and let rest for 3 before serving.","timer":240},{"title":"Garnish and Serve","text":"Scatter the freshly chopped chives over the top and serve immediately while hot and bubbling. Serve directly from the baking dish for a rustic, impressive presentation.","timer":0}]', '[{"original":"Gruyère cheese","swap":"Fontina, Gouda, or Monterey Jack for a milder flavor"},{"original":"Heavy whipping cream","swap":"Full-fat coconut cream for a dairy-free version"},{"original":"Cream cheese","swap":"Mascarpone cheese for a richer, silkier sauce"},{"original":"Bacon topping","swap":"Pancetta or diced prosciutto for an Italian twist"},{"original":"Smoked paprika","swap":"Regular paprika or chipotle powder for different heat levels"},{"original":"Fresh chives","swap":"Sliced green onions or fresh parsley"}]', '["Not drying the cauliflower thoroughly after blanching, which leads to a watery, diluted sauce","Using pre-shredded bagged cheese, which contains anti-caking starches that prevent smooth melting — always shred your own","Cooking the cauliflower too long during blanching, resulting in mushy florets that fall apart","Adding the cheese to the sauce over high heat, which causes it to seize and become grainy — always use low heat","Skipping the roasting step, which removes excess moisture and adds essential caramelized flavor","Not watching the broiler closely — the topping can go from perfectly golden to burnt in under a minute"]', '["keto","low-carb","cauliflower","mac and cheese","comfort food","gluten-free","cheese","weeknight dinner","casserole","broiled","three-cheese","bacon"]', '["keto","gluten-free"]', 'keto', 'ai');
INSERT INTO recipes (title, slug, description, quick_summary, cuisine, difficulty, prep_time, cook_time, total_time, servings, calories, protein, carbs, fat, fiber, ingredients, steps, substitutions, common_mistakes, tags, dietary, category, source) VALUES ('Midnight Fire Ramen with Silky Soft-Boiled Eggs', 'midnight-fire-ramen-soft-boiled-eggs', 'When the clock strikes midnight and hunger hits like a freight train, this fiery, soul-warming ramen is your answer. Built on a deeply savory gochujang and miso broth with a swirl of chili oil, nestled with chewy noodles and crowned with a perfectly jammy soft-boiled egg that melts into the broth with every spoonful. This is the ramen that turns a quiet kitchen into a cozy sanctuary — bold, spicy, and unapologetically indulgent.', 'A bold, spicy midnight ramen with a rich gochujang-miso broth, springy noodles, and a luscious jammy egg ready in under 30.', 'Japanese-Korean Fusion', 'Easy', 10, 20, 30, 2, 620, 28, 74, 24, 5, '[{"amount":"2","unit":"large","item":"eggs","group":"Soft-Boiled Eggs"},{"amount":"2","unit":"tablespoons","item":"soy sauce","group":"Soft-Boiled Eggs"},{"amount":"1","unit":"tablespoon","item":"mirin","group":"Soft-Boiled Eggs"},{"amount":"1","unit":"cup","item":"water","group":"Soft-Boiled Eggs"},{"amount":"3","unit":"cups","item":"chicken broth or dashi stock","group":"Broth"},{"amount":"1","unit":"cup","item":"water","group":"Broth"},{"amount":"2","unit":"tablespoons","item":"gochujang (Korean chili paste)","group":"Broth"},{"amount":"1.5","unit":"tablespoons","item":"white miso paste","group":"Broth"},{"amount":"1","unit":"tablespoon","item":"soy sauce","group":"Broth"},{"amount":"1","unit":"teaspoon","item":"sesame oil","group":"Broth"},{"amount":"1","unit":"teaspoon","item":"rice vinegar","group":"Broth"},{"amount":"1","unit":"tablespoon","item":"chili oil, plus more to serve","group":"Broth"},{"amount":"4","unit":"cloves","item":"garlic, minced","group":"Broth"},{"amount":"1","unit":"inch","item":"fresh ginger, grated","group":"Broth"},{"amount":"2","unit":"portions","item":"fresh or dried ramen noodles","group":"Noodles"},{"amount":"2","unit":"stalks","item":"green onions, thinly sliced","group":"Toppings"},{"amount":"1","unit":"sheet","item":"nori, halved","group":"Toppings"},{"amount":"1","unit":"tablespoon","item":"toasted sesame seeds","group":"Toppings"},{"amount":"4","unit":"slices","item":"fish cake (narutomaki) or chashu pork","group":"Toppings"},{"amount":"1","unit":"handful","item":"bean sprouts","group":"Toppings"},{"amount":"1","unit":"tablespoon","item":"butter","group":"Toppings"},{"amount":"to taste","unit":"","item":"red pepper flakes","group":"Toppings"}]', '[{"title":"Boil and Marinate the Eggs","text":"Bring a small saucepan of water to a rolling boil. Gently lower the eggs in with a spoon and cook for exactly 6 and 30 seconds. While eggs cook, mix soy sauce, mirin, and 1 cup water in a small container. Transfer eggs to an ice bath for 5, then peel carefully. Place peeled eggs in the soy marinade and let them soak for at least 10 while you build the broth. The longer they soak, the deeper the flavor — overnight in the fridge is heavenly.","timer":390},{"title":"Sauté the Aromatics","text":"In a medium saucepan over medium heat, add a small drizzle of neutral oil. Add the minced garlic and grated ginger and sauté for 60 to 90 seconds until fragrant and just golden, stirring constantly. Don''t let them burn — that bitter edge will haunt your broth.","timer":90},{"title":"Build the Spicy Broth","text":"Add the gochujang to the garlic and ginger and stir it into the aromatics for about 30 seconds to bloom the paste and deepen its flavor. Pour in the chicken broth and water and stir to combine. Bring to a gentle simmer over medium-high heat, then reduce to medium-low. Whisk in the miso paste until fully dissolved — never boil miso, it kills the probiotics and dulls the flavor. Stir in soy sauce, rice vinegar, sesame oil, and chili oil. Taste and adjust heat with more gochujang if you want to go full inferno. Simmer gently for 10.","timer":600},{"title":"Cook the Noodles","text":"Bring a separate pot of unsalted water to a boil. Cook ramen noodles according to package directions, usually 2 to 4 for fresh and 3 to 5 for dried. Drain and divide between two deep bowls immediately — do not let them sit or they will clump.","timer":240},{"title":"Assemble and Serve","text":"Ladle the blazing hot broth generously over the noodles in each bowl. Slice the marinated soft-boiled eggs in half lengthwise and nestle them cut-side up in the broth so you can see that glorious jammy yolk. Arrange bean sprouts, fish cake or chashu slices, and nori on the side. Drop a small knob of butter into the center of the bowl for a silky richness, then drizzle extra chili oil over everything. Shower with green onions, sesame seeds, and red pepper flakes. Eat immediately, alone, in the dark, at midnight — perfection.","timer":0}]', '[{"original":"gochujang","swap":"sriracha mixed with a pinch of red miso for a similar sweet-spicy-fermented vibe"},{"original":"chicken broth","swap":"vegetable broth or instant dashi for a lighter or pescatarian version"},{"original":"fresh ramen noodles","swap":"instant ramen noodles (discard the seasoning packet), udon, or soba"},{"original":"mirin","swap":"1 teaspoon sugar dissolved in 1 teaspoon rice wine or dry sherry"},{"original":"fish cake","swap":"sliced tofu, chashu pork, rotisserie chicken, or crispy mushrooms"},{"original":"white miso","swap":"red miso for a deeper, saltier flavor or yellow miso as a middle ground"}]', '["Boiling the miso paste — always add miso off the heat or at a gentle simmer to preserve its flavor and beneficial cultures","Overcooking the eggs past 6 30 seconds — the yolk should be jammy and slightly molten, not chalky","Letting the garlic burn during sautéing — burnt garlic makes the entire broth taste bitter and acrid","Letting noodles sit too long before adding broth — they clump and absorb liquid unevenly; always add broth immediately","Skipping the ice bath for the eggs — it stops cooking instantly and makes peeling dramatically easier","Adding all the gochujang at once without tasting — spice tolerance varies wildly, build heat gradually","Using pre-shredded nori instead of a whole sheet torn by hand — it absorbs moisture better and gives a satisfying chew"]', '["midnight snack","spicy","ramen","comfort food","quick","noodles","egg","Korean-Japanese fusion","late night","soul food","under 30","bold flavors"]', '[]', 'midnight', 'ai');
INSERT INTO recipes (title, slug, description, quick_summary, cuisine, difficulty, prep_time, cook_time, total_time, servings, calories, protein, carbs, fat, fiber, ingredients, steps, substitutions, common_mistakes, tags, dietary, category, source) VALUES ('Mediterranean Greek Salad Bowl', 'mediterranean-greek-salad-bowl', 'A vibrant, sun-kissed bowl bursting with crisp vegetables, creamy feta, and plump Kalamata olives, all brought together with a bright lemon-herb vinaigrette. This authentic Greek salad celebrates the simplicity of fresh, quality ingredients — no cooking required, just pure Mediterranean magic in every bite.', 'A fresh and colorful Greek salad bowl loaded with cucumbers, tomatoes, olives, and feta, dressed in a zesty lemon-oregano vinaigrette. Ready in 15 and completely no-cook.', 'Mediterranean', 'Easy', 15, 0, 15, 4, 310, 9, 14, 26, 3, '[{"amount":"2","unit":"large","item":"English cucumbers, halved lengthwise and sliced into half-moons","group":"Salad"},{"amount":"3","unit":"cups","item":"cherry tomatoes, halved","group":"Salad"},{"amount":"1","unit":"large","item":"red onion, thinly sliced into half-rings","group":"Salad"},{"amount":"1","unit":"large","item":"green bell pepper, cored and chopped into chunks","group":"Salad"},{"amount":"1","unit":"cup","item":"Kalamata olives, pitted","group":"Salad"},{"amount":"200","unit":"g","item":"block feta cheese, cut into thick cubes","group":"Salad"},{"amount":"1","unit":"cup","item":"pepperoncini peppers, sliced","group":"Salad"},{"amount":"1/4","unit":"cup","item":"fresh flat-leaf parsley, roughly chopped","group":"Salad"},{"amount":"1/3","unit":"cup","item":"extra-virgin olive oil","group":"Dressing"},{"amount":"3","unit":"tablespoons","item":"fresh lemon juice","group":"Dressing"},{"amount":"1","unit":"tablespoon","item":"red wine vinegar","group":"Dressing"},{"amount":"2","unit":"teaspoons","item":"dried oregano","group":"Dressing"},{"amount":"1","unit":"teaspoon","item":"Dijon mustard","group":"Dressing"},{"amount":"1","unit":"clove","item":"garlic, finely minced","group":"Dressing"},{"amount":"1/2","unit":"teaspoon","item":"sea salt","group":"Dressing"},{"amount":"1/4","unit":"teaspoon","item":"freshly cracked black pepper","group":"Dressing"}]', '[{"title":"Prep the Vegetables","text":"Slice the English cucumbers into half-moons and place them in a large wide salad bowl. Halve the cherry tomatoes and add them in. Thinly slice the red onion into half-rings — if you find raw onion too pungent, soak the slices in cold water for 5, then drain and pat dry before adding. Chop the green bell pepper into generous bite-sized chunks and add to the bowl.","timer":0},{"title":"Add the Olives and Pepperoncini","text":"Scatter the pitted Kalamata olives and sliced pepperoncini peppers evenly over the vegetables. These two ingredients are the salty, briny backbone of the salad, so distribute them well throughout.","timer":0},{"title":"Whisk the Lemon-Oregano Dressing","text":"In a small bowl or a jar with a lid, combine the extra-virgin olive oil, fresh lemon juice, red wine vinegar, dried oregano, Dijon mustard, minced garlic, sea salt, and cracked black pepper. Whisk vigorously until the dressing is fully emulsified and slightly thickened, about 30 seconds. Taste and adjust seasoning — it should be bright, tangy, and herbaceous.","timer":30},{"title":"Dress and Toss the Salad","text":"Pour about two-thirds of the dressing over the salad bowl. Using clean hands or two large spoons, gently toss everything together to coat the vegetables evenly. Reserve the remaining dressing to serve on the side or to drizzle over individual bowls.","timer":0},{"title":"Top with Feta and Finish","text":"Arrange the thick cubes of feta cheese across the top of the salad — do not toss them in or they will crumble. Scatter the freshly chopped flat-leaf parsley over everything and finish with an extra pinch of dried oregano. Drizzle any remaining dressing directly over the feta. Serve immediately for maximum crunch, or let the salad rest for 5 to 10 to allow the flavors to meld beautifully.","timer":600}]', '[{"original":"English cucumber","swap":"Persian cucumbers or regular cucumbers with seeds scooped out"},{"original":"Kalamata olives","swap":"any pitted black or green olives such as Castelvetrano"},{"original":"Block feta cheese","swap":"dairy-free feta or firm tofu crumbled with a pinch of salt for a vegan option"},{"original":"Pepperoncini peppers","swap":"banana peppers or pickled jalapeños for extra heat"},{"original":"Fresh lemon juice","swap":"white wine vinegar for a slightly milder tang"},{"original":"Red wine vinegar","swap":"apple cider vinegar"},{"original":"Green bell pepper","swap":"yellow or orange bell pepper for a sweeter flavor"}]', '["Using pre-crumbled feta instead of a block — block feta is creamier, saltier, and holds its shape beautifully as a topping","Over-tossing the salad after adding feta, which causes it to crumble into the dressing and turn muddy","Using bottled lemon juice instead of fresh — fresh lemon juice makes a dramatic difference in the brightness of the dressing","Cutting vegetables too small — Greek salad is known for its chunky, rustic cuts that provide satisfying texture","Skipping the red onion soak if sensitive to raw onion — soaking in cold water for 5 removes sharpness while keeping the crunch","Dressing the salad too far in advance, which causes the cucumbers and tomatoes to release water and make the bowl watery","Using low-quality olive oil — since this is a no-cook recipe, the olive oil flavor is front and center, so use the best extra-virgin you can find"]', '["greek salad","mediterranean","no-cook","fresh","summer","healthy","vegetarian","gluten-free","quick","feta","olives","lunch","dinner","meal prep"]', '["vegetarian","gluten-free"]', 'no-cook', 'ai');
INSERT INTO recipes (title, slug, description, quick_summary, cuisine, difficulty, prep_time, cook_time, total_time, servings, calories, protein, carbs, fat, fiber, ingredients, steps, substitutions, common_mistakes, tags, dietary, category, source) VALUES ('One-Pot Creamy Tomato Basil Soup', 'one-pot-creamy-tomato-basil-soup', 'This velvety, soul-warming tomato basil soup comes together in a single pot with ripe tomatoes, fragrant basil, and a swirl of cream that transforms humble ingredients into something truly luxurious. Roasted garlic and a touch of smoked paprika deepen the flavor profile, making every spoonful taste like it simmered all day — even though it''s ready in under an hour.', 'A rich, silky tomato basil soup made entirely in one pot with pantry staples and fresh basil. Perfect for cozy weeknights, it blends into a creamy dream in under 45.', 'Italian-American', 'Easy', 10, 35, 45, 4, 280, 5, 28, 17, 5, '[{"amount":"3","unit":"tablespoons","item":"unsalted butter","group":"Base"},{"amount":"1","unit":"medium","item":"yellow onion, roughly chopped","group":"Base"},{"amount":"6","unit":"cloves","item":"garlic, minced","group":"Base"},{"amount":"2","unit":"tablespoons","item":"tomato paste","group":"Base"},{"amount":"2","unit":"28-ounce cans","item":"whole peeled San Marzano tomatoes","group":"Soup"},{"amount":"1.5","unit":"cups","item":"vegetable broth","group":"Soup"},{"amount":"1","unit":"teaspoon","item":"smoked paprika","group":"Seasoning"},{"amount":"1","unit":"teaspoon","item":"dried oregano","group":"Seasoning"},{"amount":"0.5","unit":"teaspoon","item":"red pepper flakes","group":"Seasoning"},{"amount":"1","unit":"teaspoon","item":"granulated sugar","group":"Seasoning"},{"amount":"1","unit":"teaspoon","item":"kosher salt, plus more to taste","group":"Seasoning"},{"amount":"0.5","unit":"teaspoon","item":"freshly ground black pepper","group":"Seasoning"},{"amount":"0.75","unit":"cup","item":"heavy cream","group":"Cream"},{"amount":"1","unit":"large handful","item":"fresh basil leaves, plus more for garnish","group":"Herbs"},{"amount":"2","unit":"tablespoons","item":"extra virgin olive oil, for drizzling","group":"Garnish"},{"amount":"0.25","unit":"cup","item":"freshly grated Parmesan cheese, optional","group":"Garnish"}]', '[{"title":"Sauté the aromatics","text":"Melt the butter in a large heavy-bottomed pot or Dutch oven over medium heat. Add the chopped onion and cook, stirring occasionally, until softened and translucent, about 5 to 6. Add the minced garlic and cook for another 1 to 2 until fragrant, being careful not to let it brown.","timer":480},{"title":"Build the tomato base","text":"Add the tomato paste to the pot and stir it into the onion and garlic mixture. Cook for 2, stirring constantly, until the paste darkens slightly in color — this step caramelizes the paste and adds incredible depth of flavor to the finished soup.","timer":120},{"title":"Add tomatoes and broth","text":"Pour in both cans of whole peeled tomatoes, crushing them by hand as you add them to the pot for a more rustic texture. Add the vegetable broth, smoked paprika, dried oregano, red pepper flakes, sugar, salt, and black pepper. Stir everything together to combine.","timer":60},{"title":"Simmer the soup","text":"Bring the soup to a boil over medium-high heat, then reduce to a gentle simmer. Cook uncovered for 20, stirring occasionally, until the tomatoes have completely broken down and the flavors have melded beautifully together.","timer":1200},{"title":"Blend until silky smooth","text":"Remove the pot from heat. Add the fresh basil leaves directly into the pot. Using an immersion blender, blend the soup directly in the pot until completely smooth and velvety. Alternatively, carefully transfer the soup in batches to a standing blender, blending until smooth. Return to the pot if needed.","timer":180},{"title":"Stir in the cream","text":"Return the pot to low heat. Pour in the heavy cream and stir gently to incorporate. Taste the soup and adjust seasoning with additional salt and pepper as needed. Heat through for 3 to 4 — do not boil after adding the cream as this can cause it to separate.","timer":240},{"title":"Serve and garnish","text":"Ladle the hot soup into bowls. Garnish each serving with fresh basil leaves, a drizzle of extra virgin olive oil, and a sprinkle of freshly grated Parmesan cheese if desired. Serve immediately with crusty bread or grilled cheese on the side.","timer":0}]', '[{"original":"heavy cream","swap":"full-fat coconut milk for a dairy-free version"},{"original":"unsalted butter","swap":"olive oil for a vegan and lighter option"},{"original":"San Marzano canned tomatoes","swap":"2 pounds fresh ripe Roma tomatoes, halved and roasted at 400°F for 25"},{"original":"vegetable broth","swap":"water with an extra pinch of salt and a Parmesan rind simmered in"},{"original":"fresh basil","swap":"2 teaspoons dried basil added with the other dried herbs"}]', '["Skipping the tomato paste step — cooking it briefly in butter unlocks a depth of umami that makes the whole soup taste richer","Boiling the soup after adding cream, which can cause it to curdle or separate; always keep the heat on low","Not blending long enough — for a truly silky texture, blend for a full 60 seconds until no chunks remain","Using watery or low-quality canned tomatoes; San Marzano or a high-quality brand makes a noticeable difference in sweetness and flavor","Under-seasoning — tomatoes need adequate salt and a pinch of sugar to balance their natural acidity, so always taste before serving"]', '["tomato soup","basil","creamy","one-pot","comfort food","weeknight dinner","vegetarian","blended soup","Italian-inspired","fall","winter","cozy"]', '["vegetarian"]', 'one-pot', 'ai');
INSERT INTO recipes (title, slug, description, quick_summary, cuisine, difficulty, prep_time, cook_time, total_time, servings, calories, protein, carbs, fat, fiber, ingredients, steps, substitutions, common_mistakes, tags, dietary, category, source) VALUES ('Power-Packed Lemon Herb Chicken & Quinoa Recovery Bowl', 'lemon-herb-chicken-quinoa-recovery-bowl', 'A vibrant, nutrient-dense post-workout bowl loaded with perfectly seared lemon herb chicken breast, fluffy tri-color quinoa, roasted sweet potato, crisp cucumber, creamy avocado, and a zesty tahini-lemon drizzle. Every ingredient is chosen to replenish glycogen stores, deliver fast-absorbing protein, and reduce exercise-induced inflammation — making this the ultimate recovery meal that actually tastes incredible.', 'Juicy lemon herb chicken over fluffy quinoa with roasted sweet potato, fresh veggies, and a creamy tahini drizzle — the perfect post-workout recovery bowl ready in 35.', 'American Fusion', 'Easy', 10, 25, 35, 2, 620, 52, 58, 18, 9, '[{"amount":"2","unit":"medium","item":"boneless skinless chicken breasts (about 6 oz each)","group":"Chicken"},{"amount":"2","unit":"tablespoons","item":"olive oil, divided","group":"Chicken"},{"amount":"2","unit":"cloves","item":"garlic, minced","group":"Chicken"},{"amount":"1","unit":"teaspoon","item":"dried oregano","group":"Chicken"},{"amount":"1","unit":"teaspoon","item":"smoked paprika","group":"Chicken"},{"amount":"0.5","unit":"teaspoon","item":"ground cumin","group":"Chicken"},{"amount":"1","unit":"whole","item":"lemon, zested and juiced","group":"Chicken"},{"amount":"0.5","unit":"teaspoon","item":"kosher salt","group":"Chicken"},{"amount":"0.25","unit":"teaspoon","item":"black pepper","group":"Chicken"},{"amount":"1","unit":"cup","item":"tri-color quinoa, rinsed","group":"Quinoa"},{"amount":"2","unit":"cups","item":"low-sodium chicken broth","group":"Quinoa"},{"amount":"1","unit":"clove","item":"garlic, smashed","group":"Quinoa"},{"amount":"0.25","unit":"teaspoon","item":"salt","group":"Quinoa"},{"amount":"1","unit":"large","item":"sweet potato, peeled and diced into 1-inch cubes","group":"Roasted Vegetables"},{"amount":"1","unit":"tablespoon","item":"olive oil","group":"Roasted Vegetables"},{"amount":"0.25","unit":"teaspoon","item":"cinnamon","group":"Roasted Vegetables"},{"amount":"0.25","unit":"teaspoon","item":"salt","group":"Roasted Vegetables"},{"amount":"1","unit":"cup","item":"baby spinach, fresh","group":"Bowl Base"},{"amount":"0.5","unit":"whole","item":"English cucumber, sliced into half-moons","group":"Bowl Toppings"},{"amount":"1","unit":"whole","item":"ripe avocado, sliced","group":"Bowl Toppings"},{"amount":"0.25","unit":"cup","item":"cherry tomatoes, halved","group":"Bowl Toppings"},{"amount":"2","unit":"tablespoons","item":"pumpkin seeds (pepitas)","group":"Bowl Toppings"},{"amount":"2","unit":"tablespoons","item":"tahini","group":"Tahini Drizzle"},{"amount":"2","unit":"tablespoons","item":"fresh lemon juice","group":"Tahini Drizzle"},{"amount":"1","unit":"tablespoon","item":"water (more to thin if needed)","group":"Tahini Drizzle"},{"amount":"1","unit":"clove","item":"garlic, grated","group":"Tahini Drizzle"},{"amount":"1","unit":"teaspoon","item":"honey or maple syrup","group":"Tahini Drizzle"},{"amount":"1","unit":"pinch","item":"salt","group":"Tahini Drizzle"},{"amount":"2","unit":"tablespoons","item":"fresh parsley, chopped","group":"Garnish"},{"amount":"0.5","unit":"teaspoon","item":"red pepper flakes (optional)","group":"Garnish"}]', '[{"title":"Preheat Oven & Prep Sweet Potato","text":"Preheat your oven to 425°F (220°C). Toss the diced sweet potato with 1 tablespoon olive oil, cinnamon, and salt on a rimmed baking sheet. Spread into a single layer ensuring no pieces are overlapping — this is key for caramelization rather than steaming.","timer":120},{"title":"Roast Sweet Potato","text":"Roast the sweet potato in the preheated oven for 20 to 22, flipping once halfway through at the 10-minute mark, until the edges are golden and caramelized and a fork pierces through easily. Remove from oven and set aside.","timer":1320},{"title":"Cook the Quinoa","text":"While the sweet potato roasts, combine rinsed quinoa, chicken broth, smashed garlic clove, and salt in a medium saucepan. Bring to a boil over high heat, then reduce heat to low, cover tightly, and simmer for 15. Remove from heat and let steam, covered, for an additional 5. Fluff with a fork and discard the garlic clove. The quinoa is done when the germ ring (tiny white tail) has separated from each seed.","timer":1200},{"title":"Marinate the Chicken","text":"While the quinoa cooks, pat chicken breasts completely dry with paper towels — this ensures a proper sear. In a small bowl, mix together minced garlic, oregano, smoked paprika, cumin, lemon zest, half the lemon juice, 1 tablespoon olive oil, salt, and pepper. Rub the marinade thoroughly over both sides of each chicken breast, coating evenly.","timer":180},{"title":"Sear the Chicken","text":"Heat the remaining 1 tablespoon of olive oil in a large oven-safe skillet or cast iron pan over medium-high heat until shimmering but not smoking. Add the chicken breasts and sear undisturbed for 5 to 6 until a deep golden crust forms and the chicken releases easily from the pan. Flip and cook for another 5 to 6 until the internal temperature reaches 165°F (74°C) on an instant-read thermometer. If breasts are very thick, finish in the oven alongside the sweet potato for the last 5.","timer":720},{"title":"Rest the Chicken","text":"Transfer the cooked chicken to a cutting board and tent loosely with foil. Let it rest for at least 5 — this allows the juices to redistribute throughout the meat so every bite stays juicy and flavorful. Do not skip this step.","timer":300},{"title":"Make the Tahini Drizzle","text":"In a small bowl, whisk together tahini, fresh lemon juice, grated garlic, honey or maple syrup, and a pinch of salt until smooth. Add water one teaspoon at a time, whisking between additions, until the sauce is pourable but still creamy. It should coat the back of a spoon. Taste and adjust seasoning as needed.","timer":120},{"title":"Slice the Chicken","text":"Slice the rested chicken breasts against the grain into 0.5-inch thick slices. Cutting against the grain shortens the muscle fibers, making each bite significantly more tender. Squeeze the remaining lemon juice over the sliced chicken.","timer":60},{"title":"Assemble the Bowls","text":"Divide the warm quinoa evenly between two large bowls, creating a base layer. Add a handful of fresh baby spinach to one side — the residual heat from the quinoa will gently wilt it. Arrange the roasted sweet potato, sliced cucumber, halved cherry tomatoes, and sliced avocado in distinct sections around the bowl. Fan the sliced chicken breast over the top of the quinoa.","timer":120},{"title":"Finish and Serve","text":"Drizzle the tahini sauce generously over each bowl. Scatter pumpkin seeds and fresh chopped parsley over everything. Add red pepper flakes if desired. Serve immediately while the chicken and quinoa are still warm for the best recovery-meal experience.","timer":60}]', '[{"original":"Chicken breast","swap":"Turkey breast, canned chickpeas (for plant-based), or firm tofu pressed and pan-seared"},{"original":"Quinoa","swap":"Brown rice, farro (not gluten-free), or cauliflower rice for lower carbs"},{"original":"Sweet potato","swap":"Butternut squash, roasted beets, or air-fried chickpeas"},{"original":"Tahini","swap":"Almond butter thinned with lemon juice, or a Greek yogurt-based dressing for extra protein"},{"original":"Avocado","swap":"Hummus dollop or a drizzle of extra virgin olive oil"},{"original":"Chicken broth","swap":"Vegetable broth or water with a pinch of garlic powder"},{"original":"Pumpkin seeds","swap":"Sunflower seeds, hemp hearts, or slivered almonds"},{"original":"Honey","swap":"Maple syrup, agave, or omit entirely for a savory dressing"}]', '["Not rinsing the quinoa before cooking — the natural saponin coating causes a bitter, soapy taste that ruins the dish","Skipping the chicken resting period and cutting immediately, causing all the juices to run out onto the board leaving dry meat","Crowding the sweet potato on the baking sheet so they steam instead of roasting and caramelizing properly","Using wet chicken breasts instead of patting them dry, which prevents the Maillard reaction and produces a pale, steamed texture instead of a golden sear","Adding avocado too early if meal prepping — always slice and add fresh right before eating to prevent browning","Over-whisking the tahini sauce without adding water gradually, which can cause it to seize and become thick and pasty","Cooking the quinoa on too high a heat after bringing it to a boil, causing it to be crunchy in the center and mushy on the outside","Slicing the chicken with the grain instead of against it, resulting in tough and chewy bites"]', '["post-workout","high-protein","meal-prep","quinoa bowl","chicken bowl","recovery meal","gluten-free","healthy","quick dinner","lemon herb","tahini","avocado","sweet potato","muscle building","macro-friendly","clean eating","batch cooking","Mediterranean-inspired","fitness food"]', '["high-protein","gluten-free","dairy-free","nut-free"]', 'post-workout', 'ai');
INSERT INTO recipes (title, slug, description, quick_summary, cuisine, difficulty, prep_time, cook_time, total_time, servings, calories, protein, carbs, fat, fiber, ingredients, steps, substitutions, common_mistakes, tags, dietary, category, source) VALUES ('Classic Beef Wellington for Two', 'classic-beef-wellington-for-two', 'Few dishes command as much admiration as a perfectly executed Beef Wellington. A center-cut beef tenderloin is coated in a savory mushroom duxelles and rich chicken liver pâté, then wrapped in golden, flaky puff pastry. When sliced at the table, the dramatic reveal of perfectly pink beef surrounded by earthy mushroom and buttery pastry is nothing short of showstopping. This scaled-down version is designed for two, making it the ultimate date-night centerpiece that signals serious culinary ambition and genuine affection.', 'A showstopping beef tenderloin wrapped in savory mushroom duxelles and flaky puff pastry — the ultimate date-night dinner for two.', 'British', 'Hard', 45, 35, 1 hour 20 plus 30 chilling, 2, 920, 58, 42, 58, 3, '[{"amount":"600","unit":"g","item":"center-cut beef tenderloin fillet, trimmed","group":"Wellington"},{"amount":"1","unit":"tbsp","item":"Dijon mustard","group":"Wellington"},{"amount":"1","unit":"sheet","item":"ready-rolled all-butter puff pastry","group":"Wellington"},{"amount":"2","unit":"slices","item":"prosciutto di Parma","group":"Wellington"},{"amount":"1","unit":"","item":"egg, beaten (egg wash)","group":"Wellington"},{"amount":"300","unit":"g","item":"chestnut mushrooms, very finely chopped","group":"Duxelles"},{"amount":"2","unit":"cloves","item":"garlic, minced","group":"Duxelles"},{"amount":"1","unit":"small","item":"shallot, finely minced","group":"Duxelles"},{"amount":"2","unit":"tbsp","item":"unsalted butter","group":"Duxelles"},{"amount":"1","unit":"tbsp","item":"fresh thyme leaves","group":"Duxelles"},{"amount":"2","unit":"tbsp","item":"dry sherry","group":"Duxelles"},{"amount":"1","unit":"tsp","item":"flaky sea salt","group":"Duxelles"},{"amount":"1","unit":"tsp","item":"freshly ground black pepper","group":"Duxelles"},{"amount":"1","unit":"tbsp","item":"olive oil","group":"Searing"},{"amount":"1","unit":"tsp","item":"flaky sea salt","group":"Searing"},{"amount":"1","unit":"tsp","item":"cracked black pepper","group":"Searing"},{"amount":"200","unit":"ml","item":"good-quality beef stock","group":"Red Wine Jus"},{"amount":"100","unit":"ml","item":"full-bodied red wine","group":"Red Wine Jus"},{"amount":"1","unit":"small","item":"shallot, finely sliced","group":"Red Wine Jus"},{"amount":"1","unit":"sprig","item":"fresh rosemary","group":"Red Wine Jus"},{"amount":"1","unit":"tbsp","item":"unsalted butter, cold and cubed","group":"Red Wine Jus"},{"amount":"1","unit":"tsp","item":"Worcestershire sauce","group":"Red Wine Jus"}]', '[{"title":"Sear the Beef","text":"Remove the beef tenderloin from the refrigerator 30 before cooking to bring it to room temperature. Pat it completely dry with paper towels — this is essential for a good crust. Season generously all over with flaky sea salt and cracked black pepper. Heat olive oil in a heavy skillet or cast iron pan over the highest heat until it begins to smoke. Sear the beef for 1 to 1.5 on each side, including the ends, until deeply browned all over. You want crust, not cooking — the beef should still be almost raw inside. Transfer to a plate and brush immediately and generously all over with Dijon mustard. Allow to cool completely to room temperature, then refrigerate for at least 20.","timer":360},{"title":"Make the Mushroom Duxelles","text":"While the beef cools, make the duxelles. Pulse the chestnut mushrooms in a food processor until very finely chopped, almost paste-like. Melt butter in the same skillet over medium heat. Add the shallot and garlic and cook for 2 until softened. Add the mushrooms, thyme, salt, and pepper. Cook over medium-high heat, stirring frequently, for 10 to 12 until all moisture has completely evaporated and the mixture is dark, dry, and almost paste-like. Add the dry sherry and cook for another 2 until absorbed. The duxelles must be completely dry or the pastry will be soggy. Spread onto a plate and allow to cool completely.","timer":840},{"title":"Assemble the Wellington","text":"Lay a large sheet of plastic wrap on your work surface. Arrange the two slices of prosciutto side by side on the plastic wrap, overlapping slightly, to form a rectangle wide enough to wrap the beef. Spread the cooled duxelles evenly over the prosciutto in a thin, even layer. Place the chilled mustard-coated beef at the near edge of the prosciutto. Using the plastic wrap to help you, roll the prosciutto and duxelles tightly around the beef, twisting the ends of the plastic wrap like a Christmas cracker to form a tight log. Refrigerate for 20 to firm up and hold its shape.","timer":1200},{"title":"Wrap in Pastry","text":"Preheat your oven to 220°C (425°F) and line a baking tray with parchment paper. Lay the puff pastry sheet on a lightly floured surface. Unwrap the prosciutto-wrapped beef log and place it near one edge of the pastry. Brush the pastry edges with beaten egg wash. Roll the pastry tightly around the beef, pressing the seam firmly to seal. Tuck in the ends neatly and fold them under. Place seam-side down on the prepared baking tray. Brush the entire surface generously with egg wash. Use the back of a knife to score a subtle decorative crosshatch pattern on top, being careful not to cut through. Refrigerate for 15 — this ensures crisp, even pastry.","timer":900},{"title":"Bake the Wellington","text":"Remove the Wellington from the refrigerator. Brush once more with egg wash and sprinkle lightly with flaky sea salt. Bake in the preheated oven at 220°C (425°F) for 25 to 28, until the pastry is deeply golden and an instant-read thermometer inserted into the center of the beef reads 52°C (125°F) for medium-rare. The internal temperature will rise a few degrees as it rests. If the pastry is browning too quickly, tent loosely with foil. Remove from the oven and rest uncovered on a cutting board for 10 full minutes — do not skip this step or you will lose precious juices.","timer":1680},{"title":"Make the Red Wine Jus","text":"While the Wellington bakes, prepare the jus. In a small saucepan over medium heat, combine the sliced shallot, rosemary sprig, and red wine. Bring to a boil and reduce by half, about 4. Add the beef stock and Worcestershire sauce and continue to reduce until the sauce coats the back of a spoon, about 8 to 10. Strain through a fine mesh sieve into a clean saucepan, discarding the solids. Over low heat, whisk in the cold cubed butter piece by piece until the jus is glossy and slightly thickened. Season with salt and pepper. Keep warm.","timer":840},{"title":"Slice and Serve","text":"After resting for 10, carry the Wellington to the table whole for maximum drama. Using a sharp carving knife, slice decisively and confidently in the center to reveal the beautiful pink beef surrounded by the dark duxelles and golden pastry. Serve each portion with a generous pour of the red wine jus. Pair with buttery dauphinoise potatoes and tender-stem broccoli or French green beans for a complete date-night feast.","timer":0}]', '[{"original":"Beef tenderloin","swap":"Thick-cut venison loin for a more gamey, autumnal flavor"},{"original":"Chestnut mushrooms","swap":"A blend of porcini and cremini mushrooms for deeper umami"},{"original":"Prosciutto di Parma","swap":"Serrano ham or thinly sliced smoked salmon (for a lighter twist)"},{"original":"Dry sherry in duxelles","swap":"Dry white wine or Madeira wine"},{"original":"All-butter puff pastry","swap":"Homemade rough puff pastry for extra pastry-chef credibility"},{"original":"Chicken liver pâté","swap":"Smooth store-bought pâté layered under the duxelles for added richness"}]', '["Not searing the beef at high enough heat — you want crust, not steaming. The pan must be smoking hot.","Skipping the chilling steps between stages, which causes the Wellington to lose its shape during baking.","Leaving moisture in the duxelles — cook until completely dry or the pastry will become soggy and underbaked.","Cutting into the Wellington immediately out of the oven — resting for at least 10 is non-negotiable to keep it juicy.","Overcooking the beef — use a thermometer and pull at 52°C (125°F) for perfect medium-rare after resting.","Rolling the pastry too loosely — a tight, firm roll prevents air pockets and ensures even cooking.","Using cold beef straight from the refrigerator when searing — it will cool the pan and steam instead of sear."]', '["beef wellington","date night","special occasion","tenderloin","puff pastry","mushroom duxelles","romantic dinner","impressive","British","fine dining","red wine jus","anniversary dinner"]', '[]', 'date-night', 'ai');
INSERT INTO recipes (title, slug, description, quick_summary, cuisine, difficulty, prep_time, cook_time, total_time, servings, calories, protein, carbs, fat, fiber, ingredients, steps, substitutions, common_mistakes, tags, dietary, category, source) VALUES ('Decadent Chocolate Lava Cakes', 'decadent-chocolate-lava-cakes', 'Indulge in these impossibly rich, restaurant-worthy chocolate lava cakes with a gloriously molten center that flows like liquid silk the moment you break through the perfectly set exterior. Made with just five pantry staples, this showstopping dessert proves that extraordinary indulgence never requires complexity. Whether you''re impressing dinner guests or treating yourself to a luxurious weeknight escape, these individual cakes deliver pure chocolate euphoria in under 30.', 'Five-ingredient molten chocolate lava cakes with a gooey, flowing center — an elegant dessert ready in under 30.', 'French', 'Medium', 10, 12, 22, 4, 480, 7, 38, 34, 3, '[{"amount":"170","unit":"g","item":"dark chocolate (70% cocoa), roughly chopped","group":"Batter"},{"amount":"115","unit":"g","item":"unsalted butter, cut into cubes","group":"Batter"},{"amount":"2","unit":"whole","item":"large eggs plus 2 egg yolks","group":"Batter"},{"amount":"80","unit":"g","item":"powdered sugar, sifted","group":"Batter"},{"amount":"2","unit":"tablespoons","item":"all-purpose flour","group":"Batter"}]', '[{"title":"Prep the Ramekins","text":"Preheat your oven to 220°C (425°F). Generously butter four 170ml (6oz) ramekins, then dust each one with cocoa powder or a pinch of flour, tapping out any excess. Place the prepared ramekins on a baking sheet and set aside. Proper greasing is essential — it ensures your lava cakes release cleanly and dramatically at the table.","timer":0},{"title":"Melt Chocolate and Butter","text":"Combine the chopped dark chocolate and cubed butter in a heatproof bowl. Set the bowl over a saucepan of gently simmering water, making sure the bowl does not touch the water. Stir slowly and continuously until both are fully melted and the mixture is glossy and smooth. Remove from the heat and allow to cool for 3 to 4 so it''s warm but not scorching hot.","timer":240},{"title":"Whisk the Eggs and Sugar","text":"In a separate large mixing bowl, whisk together the whole eggs, egg yolks, and sifted powdered sugar vigorously for about 2 until the mixture turns pale, slightly thickened, and ribbon-like in texture. This step incorporates air into the batter, giving the outer cake its delicate, set structure while keeping the center luxuriously molten.","timer":120},{"title":"Combine and Add Flour","text":"Pour the warm chocolate-butter mixture into the egg and sugar mixture, folding gently with a spatula until just combined. Sift the flour directly over the top and fold in with care, using slow, sweeping motions. Mix only until no streaks of flour remain — overmixing will overdevelop the gluten and toughen the cakes. The batter should look smooth, dark, and deeply glossy.","timer":60},{"title":"Fill and Bake","text":"Divide the batter evenly among the four prepared ramekins, filling each about three-quarters full. Transfer the baking sheet to the preheated oven and bake for 11 to 13. The edges should appear fully set and slightly pulling away from the sides, while the center should still have a distinct jiggle when gently shaken. For a more liquid center, bake for 11; for a slightly thicker flow, bake for 13.","timer":720},{"title":"Rest and Unmold","text":"Remove the cakes from the oven and allow them to rest in the ramekins for exactly 1 minute — no longer, or the centers will begin to set. Run a thin knife gently around the edge of each ramekin. Place a small serving plate face-down over each ramekin, then confidently invert in one swift motion. Hold for 10 seconds, then lift the ramekin away. Serve immediately with a dusting of powdered sugar, a scoop of vanilla ice cream, or fresh berries.","timer":60}]', '[{"original":"dark chocolate (70% cocoa)","swap":"Semi-sweet chocolate chips work in a pinch, though the flavor will be slightly sweeter and less complex"},{"original":"unsalted butter","swap":"Vegan butter (such as Miyoko''s) for a dairy-free version — results are nearly identical in texture"},{"original":"all-purpose flour","swap":"Use 1.5 tablespoons of cornstarch (cornflour) for a gluten-free version with an even silkier texture"},{"original":"powdered sugar","swap":"Superfine (caster) sugar can be used though it may leave a very slightly grainier texture"},{"original":"whole eggs plus yolks","swap":"For a richer result, use 4 egg yolks only — the center will be even more custard-like and luscious"}]', '["Overbaking is the number one mistake — even one extra minute can turn a molten lava cake into a regular chocolate cake with no flowing center","Not greasing the ramekins thoroughly enough, causing the cakes to stick and collapse upon unmolding","Adding the eggs to chocolate that is still too hot, which can scramble the eggs and ruin the batter","Skipping the resting period after baking — 1 minute of rest helps the exterior firm up just enough to hold its shape when unmolded","Using chocolate with less than 60% cocoa content, which makes the batter too sweet and the structure too soft","Filling the ramekins too full, causing the batter to overflow during baking and leaving no room for the molten center to develop properly"]', '["chocolate","lava cake","molten","dessert","5-ingredient","quick","dinner party","romantic","indulgent","baked"]', '["vegetarian"]', '5-ingredient', 'ai');
INSERT INTO recipes (title, slug, description, quick_summary, cuisine, difficulty, prep_time, cook_time, total_time, servings, calories, protein, carbs, fat, fiber, ingredients, steps, substitutions, common_mistakes, tags, dietary, category, source) VALUES ('Herb-Crusted Grilled Salmon with Balsamic Roasted Vegetables', 'herb-crusted-grilled-salmon-balsamic-roasted-vegetables', 'A vibrant, nutrient-rich dish featuring omega-3-packed salmon fillets seasoned with a fragrant herb crust, paired with a colorful medley of low-glycemic roasted vegetables finished with a tangy balsamic glaze. This diabetic-friendly meal is designed to keep blood sugar stable while delivering bold, satisfying flavors that prove healthy eating never has to feel like a compromise.', 'Perfectly grilled herb-crusted salmon paired with colorful balsamic roasted vegetables — a blood-sugar-friendly powerhouse meal ready in under 45.', 'Mediterranean', 'Easy', 15, 25, 40, 4, 380, 42, 18, 16, 5, '[{"amount":"4","unit":"fillets (6 oz each)","item":"wild-caught salmon fillets, skin-on","group":"Salmon"},{"amount":"2","unit":"tablespoons","item":"extra-virgin olive oil","group":"Salmon"},{"amount":"2","unit":"cloves","item":"garlic, minced","group":"Salmon"},{"amount":"1","unit":"tablespoon","item":"fresh rosemary, finely chopped","group":"Salmon"},{"amount":"1","unit":"tablespoon","item":"fresh thyme leaves","group":"Salmon"},{"amount":"1","unit":"tablespoon","item":"fresh flat-leaf parsley, finely chopped","group":"Salmon"},{"amount":"1","unit":"teaspoon","item":"lemon zest","group":"Salmon"},{"amount":"1","unit":"tablespoon","item":"fresh lemon juice","group":"Salmon"},{"amount":"0.5","unit":"teaspoon","item":"smoked paprika","group":"Salmon"},{"amount":"0.5","unit":"teaspoon","item":"black pepper, freshly ground","group":"Salmon"},{"amount":"0.25","unit":"teaspoon","item":"sea salt","group":"Salmon"},{"amount":"1","unit":"medium","item":"zucchini, sliced into half-moons","group":"Roasted Vegetables"},{"amount":"1","unit":"medium","item":"red bell pepper, cut into 1-inch pieces","group":"Roasted Vegetables"},{"amount":"1","unit":"medium","item":"yellow bell pepper, cut into 1-inch pieces","group":"Roasted Vegetables"},{"amount":"1","unit":"cup","item":"cherry tomatoes, halved","group":"Roasted Vegetables"},{"amount":"1","unit":"medium","item":"red onion, cut into wedges","group":"Roasted Vegetables"},{"amount":"1","unit":"cup","item":"broccoli florets","group":"Roasted Vegetables"},{"amount":"2","unit":"tablespoons","item":"extra-virgin olive oil","group":"Roasted Vegetables"},{"amount":"2","unit":"tablespoons","item":"balsamic vinegar (no sugar added)","group":"Roasted Vegetables"},{"amount":"1","unit":"teaspoon","item":"dried Italian seasoning","group":"Roasted Vegetables"},{"amount":"0.25","unit":"teaspoon","item":"sea salt","group":"Roasted Vegetables"},{"amount":"0.25","unit":"teaspoon","item":"black pepper","group":"Roasted Vegetables"},{"amount":"4","unit":"wedges","item":"fresh lemon, for serving","group":"Garnish"},{"amount":"2","unit":"tablespoons","item":"fresh parsley, chopped, for garnish","group":"Garnish"}]', '[{"title":"Preheat Oven","text":"Preheat your oven to 425°F (220°C). Line a large rimmed baking sheet with parchment paper and set aside. A hot oven ensures the vegetables caramelize beautifully rather than steam.","timer":0},{"title":"Prepare the Roasted Vegetables","text":"In a large mixing bowl, combine the zucchini, red and yellow bell peppers, cherry tomatoes, red onion, and broccoli florets. Drizzle with 2 tablespoons of olive oil and balsamic vinegar. Sprinkle with Italian seasoning, sea salt, and black pepper. Toss everything together until the vegetables are evenly coated.","timer":0},{"title":"Roast the Vegetables","text":"Spread the seasoned vegetables in a single layer on the prepared baking sheet, making sure they are not overlapping to ensure even roasting. Place in the preheated oven and roast for 20 to 25, tossing once halfway through, until the edges are golden and slightly caramelized.","timer":1500},{"title":"Make the Herb Crust","text":"While the vegetables roast, prepare the herb crust for the salmon. In a small bowl, combine the minced garlic, rosemary, thyme, parsley, lemon zest, lemon juice, smoked paprika, black pepper, and sea salt. Stir in 2 tablespoons of olive oil to form a loose paste.","timer":0},{"title":"Prepare the Salmon","text":"Pat the salmon fillets completely dry with paper towels — this is essential for achieving a good sear. Evenly spread the herb paste over the flesh side of each fillet, pressing gently to adhere. Allow the salmon to sit at room temperature for 5 to let the flavors begin to penetrate.","timer":300},{"title":"Preheat the Grill","text":"Preheat your outdoor grill or indoor grill pan over medium-high heat. Lightly brush the grates or pan with a neutral oil using a folded paper towel held with tongs. The grill is ready when a drop of water sizzles and evaporates immediately on contact.","timer":300},{"title":"Grill the Salmon","text":"Place the salmon fillets skin-side down on the hot grill. Cook for 4 to 5 without moving until the skin is crispy and releases naturally from the grill. Carefully flip and cook flesh-side down for an additional 3 to 4, or until the salmon reaches an internal temperature of 145°F (63°C) and flakes easily with a fork. Avoid overcooking to maintain moisture.","timer":480},{"title":"Rest and Plate","text":"Remove the salmon from the grill and let it rest for 2. Remove the roasted vegetables from the oven. Divide the roasted vegetables evenly among four plates and place one salmon fillet alongside each portion. Garnish with fresh chopped parsley and serve immediately with a wedge of fresh lemon for squeezing over the top.","timer":120}]', '[{"original":"wild-caught salmon","swap":"skinless cod, tilapia, or trout fillets for a milder flavor with similar protein content"},{"original":"balsamic vinegar","swap":"apple cider vinegar for a slightly lower glycemic option"},{"original":"zucchini","swap":"yellow squash or asparagus spears"},{"original":"red bell pepper","swap":"orange bell pepper or thinly sliced fennel"},{"original":"fresh rosemary and thyme","swap":"2 teaspoons of pre-made no-salt herb blend such as Herbs de Provence"},{"original":"cherry tomatoes","swap":"diced Roma tomatoes or sun-dried tomatoes packed in water"},{"original":"broccoli florets","swap":"cauliflower florets or green beans"}]', '["Not drying the salmon fillets before applying the herb crust, which causes the paste to slide off and prevents proper searing","Overcrowding the baking sheet with vegetables, causing them to steam instead of roast and caramelize","Flipping the salmon too early before it naturally releases from the grill grates, which tears the flesh and removes the crust","Overcooking the salmon past 145°F which makes it dry and tough — use an instant-read thermometer for accuracy","Using a cold grill pan which causes the salmon to stick and cook unevenly — always preheat thoroughly","Skipping the resting period after grilling which causes the juices to run out immediately when the fillet is cut","Using sweetened balsamic glaze or regular balsamic reduction with added sugars, which can spike blood glucose levels"]', '["diabetic-friendly","grilled salmon","roasted vegetables","low-glycemic","heart-healthy","high-protein","gluten-free","omega-3","Mediterranean","weeknight dinner","blood sugar friendly","low-carb","clean eating","meal prep"]', '["diabetic","high-protein","gluten-free"]', 'diabetic', 'ai');
INSERT INTO recipes (title, slug, description, quick_summary, cuisine, difficulty, prep_time, cook_time, total_time, servings, calories, protein, carbs, fat, fiber, ingredients, steps, substitutions, common_mistakes, tags, dietary, category, source) VALUES ('Sneaky Garden Pasta Sauce', 'sneaky-garden-pasta-sauce', 'A rich, velvety tomato pasta sauce that hides a rainbow of vegetables so cleverly that even the pickiest little eaters will ask for seconds. Spinach and carrots melt seamlessly into a deep, sweet tomato base, delivering a powerhouse of nutrition in every spoonful without anyone being the wiser. This is weeknight magic in a pot.', 'A clever veggie-packed tomato sauce blending spinach and carrots into a silky, kid-approved pasta topper ready in under 40.', 'Italian-American', 'Easy', 10, 25, 35, 6, 145, 4g, 18g, 6g, 4g, '[{"amount":"3","unit":"tablespoons","item":"olive oil","group":"Base"},{"amount":"1","unit":"medium","item":"yellow onion, roughly chopped","group":"Base"},{"amount":"4","unit":"cloves","item":"garlic, minced","group":"Base"},{"amount":"2","unit":"medium","item":"carrots, peeled and roughly chopped","group":"Hidden Veggies"},{"amount":"3","unit":"cups","item":"fresh baby spinach, packed","group":"Hidden Veggies"},{"amount":"2","unit":"cans (28 oz each)","item":"crushed San Marzano tomatoes","group":"Sauce"},{"amount":"2","unit":"tablespoons","item":"tomato paste","group":"Sauce"},{"amount":"1","unit":"teaspoon","item":"granulated sugar","group":"Seasoning"},{"amount":"1","unit":"teaspoon","item":"dried oregano","group":"Seasoning"},{"amount":"1","unit":"teaspoon","item":"dried basil","group":"Seasoning"},{"amount":"0.5","unit":"teaspoon","item":"fine sea salt","group":"Seasoning"},{"amount":"0.25","unit":"teaspoon","item":"black pepper","group":"Seasoning"},{"amount":"0.5","unit":"cup","item":"whole milk or heavy cream","group":"Finishing"},{"amount":"0.25","unit":"cup","item":"freshly grated Parmesan cheese","group":"Finishing"},{"amount":"1","unit":"pound","item":"penne or rigatoni pasta, cooked to serve","group":"To Serve"}]', '[{"title":"Soften the aromatics","text":"Heat olive oil in a large heavy-bottomed saucepan or Dutch oven over medium heat. Add the chopped onion and carrots and cook, stirring occasionally, until the onion is translucent and the carrots have softened, about 8. The carrots must be genuinely soft before blending or they will leave a grainy texture in the final sauce.","timer":480},{"title":"Add garlic and tomato paste","text":"Push the vegetables to one side of the pan and add the minced garlic directly to the oil. Cook for 60 seconds until fragrant, then stir in the tomato paste. Cook the paste for 2, stirring constantly, until it darkens slightly in color and becomes fragrant. This step builds a deep, caramelized tomato flavor that makes the sauce taste slow-cooked.","timer":180},{"title":"Build the sauce","text":"Pour in both cans of crushed tomatoes and stir everything together well. Add the sugar, dried oregano, dried basil, salt, and black pepper. Stir to combine, then bring the sauce to a gentle simmer over medium heat. Reduce heat to medium-low and let it bubble gently, uncovered, for 10 to meld the flavors.","timer":600},{"title":"Wilt in the spinach","text":"Add all of the baby spinach directly into the simmering sauce in two or three large handfuls. Stir each handful in and let it wilt completely before adding the next. Within about 2 all the spinach will have collapsed into the sauce. Do not worry if it looks like a lot — it will disappear completely after blending.","timer":120},{"title":"Blend until silky smooth","text":"Remove the pan from the heat. Using an immersion blender, carefully blend the sauce directly in the pot until completely smooth with no visible vegetable pieces, about 1 to 2. Alternatively, let the sauce cool slightly then blend in batches in a countertop blender, filling it no more than halfway and holding the lid firmly with a folded kitchen towel. A completely smooth texture is the key to keeping the vegetables invisible.","timer":120},{"title":"Finish with cream and Parmesan","text":"Return the blended sauce to medium-low heat. Stir in the whole milk or heavy cream and the grated Parmesan cheese. Simmer gently for 3 to 4, stirring, until the sauce is silky, slightly thickened, and a beautiful deep orange-red color. Taste and adjust salt if needed. The cream rounds out any bitterness and gives the sauce a luxurious, restaurant-quality richness that kids absolutely love.","timer":240},{"title":"Toss and serve","text":"Add your cooked pasta directly into the sauce and toss to coat every piece thoroughly. Serve immediately in bowls with an extra sprinkle of Parmesan on top. For extra fun, serve with garlic bread cut into dipping sticks.","timer":60}]', '[{"original":"fresh baby spinach","swap":"frozen spinach, thawed and squeezed dry — use 1 cup packed"},{"original":"carrots","swap":"butternut squash or sweet potato, diced small and cooked until very tender"},{"original":"whole milk or heavy cream","swap":"unsweetened oat milk or coconut cream for a dairy-free version"},{"original":"Parmesan cheese","swap":"nutritional yeast for a vegan and dairy-free option"},{"original":"crushed San Marzano tomatoes","swap":"any good quality crushed tomatoes or blended whole peeled tomatoes"},{"original":"penne or rigatoni","swap":"any pasta shape works — try bowties or shells for extra kid appeal"}]', '["Not cooking the carrots long enough before blending — undercooked carrots leave a gritty texture that older kids especially will notice","Skipping the tomato paste caramelization step — this is where most of the deep flavor comes from so do not rush it","Blending while the sauce is too hot without a proper lid hold — hot liquids expand rapidly in a blender and can cause dangerous splattering","Adding the cream over too-high heat which can cause it to separate — always reduce to a gentle simmer before stirring it in","Over-salting before tasting at the end since Parmesan adds significant saltiness on its own","Using a blender that is too full — always blend hot liquids in small batches to avoid overflow and burns"]', '["hidden veggies","pasta sauce","kid-friendly","sneaky nutrition","tomato sauce","weeknight dinner","family meal","spinach","carrots","blended sauce","picky eaters","make-ahead"]', '["vegetarian"]', 'kids', 'ai');
INSERT INTO recipes (title, slug, description, quick_summary, cuisine, difficulty, prep_time, cook_time, total_time, servings, calories, protein, carbs, fat, fiber, ingredients, steps, substitutions, common_mistakes, tags, dietary, category, source) VALUES ('The Ultimate Hangover Cure Breakfast Burrito', 'hangover-cure-loaded-breakfast-burrito', 'When the morning after hits hard, this loaded breakfast burrito is your salvation. Packed with scrambled eggs, crispy bacon, golden hash browns, melted cheddar, creamy avocado, and a fiery chipotle salsa, every single bite is engineered to bring you back to life. The combination of complex carbs, protein, healthy fats, and electrolyte-rich ingredients works together to replenish what last night stole from you. This is not just breakfast — this is recovery fuel wrapped in a warm, toasty tortilla.', 'A massive, flavor-packed breakfast burrito loaded with eggs, bacon, hash browns, cheese, and avocado designed specifically to cure what ails you the morning after.', 'Tex-Mex', 'Medium', 15, 25, 40, 2, 820, 42, 68, 44, 8, '[{"amount":"4","unit":"large","item":"eggs","group":"egg mixture"},{"amount":"2","unit":"tablespoons","item":"whole milk","group":"egg mixture"},{"amount":"0.5","unit":"teaspoon","item":"garlic powder","group":"egg mixture"},{"amount":"0.5","unit":"teaspoon","item":"onion powder","group":"egg mixture"},{"amount":"0.25","unit":"teaspoon","item":"black pepper","group":"egg mixture"},{"amount":"0.25","unit":"teaspoon","item":"salt","group":"egg mixture"},{"amount":"6","unit":"strips","item":"thick-cut bacon","group":"protein"},{"amount":"1","unit":"cup","item":"shredded hash browns, thawed if frozen","group":"hash browns"},{"amount":"0.5","unit":"teaspoon","item":"smoked paprika","group":"hash browns"},{"amount":"1","unit":"tablespoon","item":"olive oil","group":"hash browns"},{"amount":"1","unit":"cup","item":"shredded sharp cheddar cheese","group":"cheese"},{"amount":"1","unit":"large","item":"ripe avocado, sliced","group":"toppings"},{"amount":"1","unit":"tablespoon","item":"fresh lime juice","group":"toppings"},{"amount":"0.5","unit":"cup","item":"canned black beans, drained and rinsed","group":"toppings"},{"amount":"0.5","unit":"cup","item":"chipotle salsa","group":"toppings"},{"amount":"0.25","unit":"cup","item":"sour cream","group":"toppings"},{"amount":"2","unit":"tablespoons","item":"fresh cilantro, chopped","group":"toppings"},{"amount":"2","unit":"large","item":"flour tortillas, 12-inch burrito size","group":"wrap"},{"amount":"1","unit":"tablespoon","item":"unsalted butter","group":"cooking"},{"amount":"1","unit":"tablespoon","item":"hot sauce, such as Cholula or Tapatio","group":"toppings"}]', '[{"title":"Cook the Bacon","text":"Lay the bacon strips in a cold skillet and place over medium heat. Cook for 8 to 10, flipping occasionally, until the bacon is deeply golden and crispy. Transfer to a paper-towel-lined plate and drain the excess fat from the pan, leaving about 1 teaspoon of bacon drippings behind. Once cool enough to handle, roughly chop the bacon into bite-sized pieces and set aside.","timer":600},{"title":"Crisp Up the Hash Browns","text":"Add the olive oil to the same skillet with the reserved bacon drippings over medium-high heat. Add the shredded hash browns in an even layer, season with smoked paprika, salt, and a pinch of black pepper. Press down firmly with a spatula. Cook undisturbed for 4 to 5 until the bottom is golden and crispy, then flip in sections and cook another 3 to 4. The crispier the better — those crunchy bits add incredible texture. Remove from heat and set aside.","timer":540},{"title":"Warm the Black Beans","text":"In a small saucepan over low heat, warm the drained black beans with a pinch of cumin, salt, and a splash of water. Stir occasionally for about 3 until heated through. Remove from heat and keep covered.","timer":180},{"title":"Scramble the Eggs","text":"In a bowl, whisk together the eggs, milk, garlic powder, onion powder, salt, and pepper until fully combined and slightly frothy. Melt the butter in a non-stick skillet over medium-low heat. Pour in the egg mixture and let it sit for 30 seconds before gently folding with a spatula. Continue folding slowly, pulling the eggs from the edges to the center, cooking for 3 to 4 total. Remove from heat just before they look fully done — residual heat will finish them. You want soft, pillowy, custardy curds, not rubbery eggs.","timer":240},{"title":"Prep the Avocado","text":"While the eggs are cooking, slice the avocado in half, remove the pit, and scoop the flesh. Slice or mash according to your preference. Toss the avocado with fresh lime juice to prevent browning and add a bright, fresh flavor that cuts through the richness of everything else.","timer":60},{"title":"Warm the Tortillas","text":"Place each flour tortilla directly over a gas burner flame for 20 to 30 seconds per side, or warm in a dry skillet over medium heat for about 1 minute per side. You want them pliable and lightly charred in spots — this makes them much easier to roll and adds a smoky depth of flavor.","timer":60},{"title":"Assemble the Burritos","text":"Lay a warm tortilla flat on a clean surface. Down the center, layer half the shredded cheddar first — the warmth of the ingredients will melt it. Add half the scrambled eggs, half the crispy hash browns, half the chopped bacon, and half the warmed black beans. Top with avocado slices, a generous spoonful of chipotle salsa, sour cream, fresh cilantro, and a good drizzle of hot sauce. Repeat for the second burrito.","timer":120},{"title":"Roll and Toast the Burritos","text":"Fold the sides of the tortilla inward over the filling, then roll tightly from the bottom up, tucking as you go to keep everything contained. Place the burrito seam-side down in a dry skillet or griddle over medium heat. Toast for 2 per side until golden and sealed. This crucial step locks everything in and gives the outside a satisfying crunch.","timer":240},{"title":"Serve and Recover","text":"Slice the burrito diagonally in half and serve immediately with extra chipotle salsa and hot sauce on the side. Pair with a large glass of cold water, coconut water, or a Bloody Mary if you are feeling brave. Eat slowly, breathe, and let the healing begin.","timer":0}]', '[{"original":"bacon","swap":"turkey bacon or plant-based bacon for a lighter option"},{"original":"flour tortilla","swap":"whole wheat tortilla for added fiber and nutrients"},{"original":"sour cream","swap":"Greek yogurt for extra protein and a probiotic boost"},{"original":"cheddar cheese","swap":"pepper jack cheese for extra heat and spice"},{"original":"black beans","swap":"pinto beans or refried beans for a creamier texture"},{"original":"chipotle salsa","swap":"pico de gallo or green tomatillo salsa"},{"original":"fresh cilantro","swap":"flat-leaf parsley if you are a cilantro avoider"}]', '["Overcooking the eggs — remove them from heat while they still look slightly underdone as they will continue cooking from residual heat","Skipping the tortilla toasting step — this is essential to seal the burrito and prevent a soggy, falling-apart mess","Not patting the hash browns dry before cooking — excess moisture leads to steaming instead of crisping","Overfilling the burrito — be generous but leave enough tortilla border to actually fold and roll the thing shut","Assembling on a cold tortilla — always warm the tortilla first or it will crack and tear when you try to roll it","Using watery salsa — opt for a thicker chunky salsa to avoid a soggy burrito","Not seasoning each component separately — every layer needs its own salt and pepper for the flavors to pop"]', '["hangover cure","breakfast burrito","loaded burrito","morning after","egg burrito","bacon burrito","tex-mex breakfast","hearty breakfast","weekend brunch","recovery food","comfort food","high protein breakfast"]', '["high-protein"]', 'hangover', 'ai');
INSERT INTO recipes (title, slug, description, quick_summary, cuisine, difficulty, prep_time, cook_time, total_time, servings, calories, protein, carbs, fat, fiber, ingredients, steps, substitutions, common_mistakes, tags, dietary, category, source) VALUES ('Turmeric Golden Milk Latte', 'turmeric-golden-milk-latte', 'A warmly spiced, velvety golden milk latte crafted with anti-inflammatory turmeric, creamy oat milk, and a fragrant blend of cinnamon, ginger, and black pepper. This soothing beverage is not only a feast for the eyes with its stunning golden hue, but it also delivers a powerful punch of wellness benefits in every luxurious sip. Whether you enjoy it as a morning ritual, an afternoon pick-me-up, or a calming evening wind-down, this latte is your golden ticket to feeling nourished from the inside out.', 'A creamy, spiced vegan latte made with turmeric and oat milk that soothes inflammation and warms the soul in under 10.', 'Ayurvedic-Inspired', 'Easy', 3, 7, 10, 2, 145, 3, 22, 5, 1, '[{"amount":"2","unit":"cups","item":"unsweetened oat milk","group":"Base"},{"amount":"1/2","unit":"cup","item":"full-fat coconut milk (canned)","group":"Base"},{"amount":"1.5","unit":"tsp","item":"ground turmeric","group":"Spice Blend"},{"amount":"1","unit":"tsp","item":"ground cinnamon","group":"Spice Blend"},{"amount":"1/2","unit":"tsp","item":"fresh ginger, finely grated","group":"Spice Blend"},{"amount":"1/4","unit":"tsp","item":"ground black pepper","group":"Spice Blend"},{"amount":"1/8","unit":"tsp","item":"ground cardamom","group":"Spice Blend"},{"amount":"1","unit":"pinch","item":"cayenne pepper (optional)","group":"Spice Blend"},{"amount":"1.5","unit":"tbsp","item":"pure maple syrup","group":"Sweetener"},{"amount":"1/2","unit":"tsp","item":"pure vanilla extract","group":"Flavor"},{"amount":"1","unit":"tsp","item":"coconut oil (unrefined)","group":"Healthy Fat"}]', '[{"title":"Combine Milks","text":"Pour the oat milk and canned coconut milk into a small saucepan over medium-low heat. Stir gently to combine as the mixture begins to warm.","timer":60},{"title":"Add the Spice Blend","text":"Once the milk mixture is warm but not boiling, whisk in the ground turmeric, cinnamon, grated ginger, black pepper, and cardamom. Add the optional pinch of cayenne if you enjoy a subtle warming kick. Whisk vigorously to ensure no lumps remain and the spices are fully incorporated.","timer":90},{"title":"Sweeten and Flavor","text":"Add the maple syrup, vanilla extract, and coconut oil to the saucepan. Continue to whisk everything together over medium-low heat. Allow the latte mixture to gently simmer — do not let it boil — so the flavors meld beautifully.","timer":180},{"title":"Froth the Latte","text":"Remove the saucepan from heat. For a frothy, cafe-style finish, use a handheld milk frother, immersion blender, or transfer carefully to a countertop blender and blend for 20 to 30 seconds until foamy and slightly thickened. Be cautious with hot liquids in a blender — leave the lid slightly ajar and cover with a towel.","timer":30},{"title":"Serve Immediately","text":"Pour the golden latte into two warmed mugs. Garnish with an extra dusting of ground cinnamon and turmeric on top of the foam. Serve immediately while hot and enjoy mindfully.","timer":0}]', '[{"original":"oat milk","swap":"almond milk, cashew milk, or hemp milk all work wonderfully as a base"},{"original":"canned coconut milk","swap":"coconut cream for an even richer texture, or omit and use all oat milk for a lighter version"},{"original":"fresh ginger","swap":"1/4 tsp ground ginger makes a convenient pantry-friendly substitute"},{"original":"maple syrup","swap":"agave nectar, date syrup, or a few pitted Medjool dates blended in for whole-food sweetness"},{"original":"coconut oil","swap":"a small spoonful of almond butter or tahini adds creaminess and healthy fats"}]', '["Boiling the milk mixture — high heat destroys beneficial compounds in turmeric and can cause the milk to develop an unpleasant skin or curdled texture","Skipping the black pepper — piperine in black pepper increases curcumin absorption from turmeric by up to 2000%, so never leave it out","Using too much turmeric — more is not always better here; excess turmeric can make the latte bitter and unpleasant rather than earthy and warm","Not whisking continuously — turmeric and spices will settle and clump at the bottom if left unstirred, leading to an uneven and gritty texture","Using low-fat or watered-down coconut milk — the fat content is important for curcumin absorption and for achieving that creamy, indulgent mouthfeel"]', '["turmeric","golden milk","latte","anti-inflammatory","wellness","vegan","dairy-free","cozy","warm drinks","Ayurvedic","immune support","gut health","fall drinks","winter drinks","quick recipe"]', '["vegan","dairy-free","gluten-free","nut-free","refined sugar-free"]', 'anti-inflammatory', 'ai');
INSERT INTO recipes (title, slug, description, quick_summary, cuisine, difficulty, prep_time, cook_time, total_time, servings, calories, protein, carbs, fat, fiber, ingredients, steps, substitutions, common_mistakes, tags, dietary, category, source) VALUES ('Sunday Meal Prep Honey Garlic Chicken with Rice and Broccoli', 'meal-prep-honey-garlic-chicken-rice-broccoli', 'This Sunday meal prep staple delivers juicy, caramelized honey garlic chicken thighs paired with fluffy jasmine rice and perfectly roasted broccoli. The sticky-sweet glaze infuses every bite with bold, savory flavor while the balanced macros make this a go-to high-protein prep that keeps well all week. Batch cook this once and enjoy five satisfying lunches or dinners without any midweek stress.', 'Sticky honey garlic chicken thighs with jasmine rice and roasted broccoli — a high-protein meal prep win that stays delicious all week.', 'Asian-American', 'Easy', 20, 40, 1 hour, 5, 520, 42, 54, 12, 4, '[{"amount":"2.5","unit":"lbs","item":"boneless skinless chicken thighs","group":"Chicken"},{"amount":"3","unit":"tablespoons","item":"honey","group":"Honey Garlic Sauce"},{"amount":"4","unit":"cloves","item":"garlic, minced","group":"Honey Garlic Sauce"},{"amount":"3","unit":"tablespoons","item":"low-sodium soy sauce","group":"Honey Garlic Sauce"},{"amount":"1","unit":"tablespoon","item":"rice vinegar","group":"Honey Garlic Sauce"},{"amount":"1","unit":"teaspoon","item":"sesame oil","group":"Honey Garlic Sauce"},{"amount":"1","unit":"teaspoon","item":"cornstarch","group":"Honey Garlic Sauce"},{"amount":"2","unit":"tablespoons","item":"water","group":"Honey Garlic Sauce"},{"amount":"1","unit":"teaspoon","item":"red pepper flakes","group":"Honey Garlic Sauce"},{"amount":"1","unit":"teaspoon","item":"kosher salt","group":"Seasoning"},{"amount":"0.5","unit":"teaspoon","item":"black pepper","group":"Seasoning"},{"amount":"0.5","unit":"teaspoon","item":"smoked paprika","group":"Seasoning"},{"amount":"1","unit":"tablespoon","item":"olive oil","group":"Cooking"},{"amount":"2","unit":"cups","item":"dry jasmine rice","group":"Rice"},{"amount":"3","unit":"cups","item":"low-sodium chicken broth","group":"Rice"},{"amount":"1","unit":"cup","item":"water","group":"Rice"},{"amount":"1","unit":"tablespoon","item":"butter","group":"Rice"},{"amount":"1.5","unit":"lbs","item":"broccoli florets, cut into bite-sized pieces","group":"Broccoli"},{"amount":"2","unit":"tablespoons","item":"olive oil","group":"Broccoli"},{"amount":"0.5","unit":"teaspoon","item":"garlic powder","group":"Broccoli"},{"amount":"0.5","unit":"teaspoon","item":"kosher salt","group":"Broccoli"},{"amount":"0.25","unit":"teaspoon","item":"black pepper","group":"Broccoli"},{"amount":"1","unit":"tablespoon","item":"sesame seeds, for garnish","group":"Garnish"},{"amount":"2","unit":"stalks","item":"green onions, thinly sliced","group":"Garnish"}]', '[{"title":"Preheat and Prep","text":"Preheat your oven to 425°F (220°C). Line two large baking sheets with parchment paper or foil and set aside. Rinse your jasmine rice under cold water until the water runs clear to remove excess starch — this ensures fluffy, separated grains.","timer":0},{"title":"Cook the Rice","text":"In a medium saucepan, combine the rinsed jasmine rice, chicken broth, 1 cup of water, and butter. Bring to a boil over high heat, then reduce to the lowest possible simmer, cover tightly, and cook for 15. Remove from heat and let steam, covered, for an additional 10. Fluff with a fork and set aside to cool before portioning.","timer":1500},{"title":"Make the Honey Garlic Sauce","text":"In a small bowl, whisk together honey, minced garlic, soy sauce, rice vinegar, sesame oil, and red pepper flakes. In a separate tiny bowl, dissolve cornstarch in 2 tablespoons of water to create a slurry, then whisk it into the sauce. This slurry will help the glaze cling beautifully to the chicken. Set aside half the sauce for glazing during cooking and reserve the other half for drizzling after.","timer":0},{"title":"Season and Sear the Chicken","text":"Pat chicken thighs completely dry with paper towels — this is crucial for a good sear and caramelization. Season both sides with kosher salt, black pepper, and smoked paprika. Heat olive oil in a large oven-safe skillet over medium-high heat until shimmering. Add chicken thighs smooth-side down and sear without moving for 4 to 5 until deeply golden brown. Flip and sear the other side for 2.","timer":420},{"title":"Roast the Broccoli","text":"While the chicken sears, toss broccoli florets with olive oil, garlic powder, salt, and pepper directly on one of the prepared baking sheets. Spread into a single layer, ensuring the florets have space to roast rather than steam. Slide into the preheated oven and roast for 20 to 22, flipping once halfway through, until the edges are crispy and slightly charred.","timer":1320},{"title":"Glaze and Bake the Chicken","text":"Pour half of the honey garlic sauce over the seared chicken thighs in the skillet, turning to coat each piece evenly. Transfer the skillet to the oven alongside the broccoli and bake at 425°F for 18 to 20, until the chicken reaches an internal temperature of 165°F and the glaze is sticky and caramelized with darkened edges. If you want extra caramelization, switch to broil for the final 2 but watch closely.","timer":1200},{"title":"Rest and Slice","text":"Remove chicken from the oven and let it rest in the pan for 5 full minutes — this allows the juices to redistribute so the meat stays moist throughout the week. After resting, slice each thigh into thirds or leave whole depending on your preference. Drizzle the reserved sauce over the chicken for extra flavor.","timer":300},{"title":"Portion Into Meal Prep Containers","text":"Divide the fluffy jasmine rice evenly among 5 airtight meal prep containers, approximately three-quarters of a cup per container. Add a portion of roasted broccoli alongside the rice. Top with sliced honey garlic chicken and drizzle any remaining pan sauce from the skillet over everything. Garnish with sesame seeds and sliced green onions. Allow containers to cool completely to room temperature before sealing and refrigerating.","timer":0}]', '[{"original":"chicken thighs","swap":"boneless skinless chicken breasts for lower fat, reduce bake time by 5"},{"original":"jasmine rice","swap":"brown rice for more fiber, increase cook time to 45"},{"original":"honey","swap":"maple syrup for a slightly earthier sweetness"},{"original":"soy sauce","swap":"coconut aminos for a soy-free and lower-sodium option"},{"original":"broccoli","swap":"broccolini, green beans, or asparagus work equally well"},{"original":"rice vinegar","swap":"apple cider vinegar in a pinch"},{"original":"sesame oil","swap":"toasted walnut oil for a different but complementary nuttiness"}]', '["Not patting the chicken dry before searing, which causes steaming instead of browning and results in a pale, less flavorful crust","Skipping the cornstarch slurry in the sauce, which makes the glaze watery and prevents it from clinging to the chicken","Overcrowding the broccoli on the baking sheet, trapping steam and making the florets soggy instead of crispy","Lifting the lid while the rice cooks, which releases steam and leads to unevenly cooked, gummy rice","Portioning the chicken while it is still hot, which causes the juices to run out and dry it out by day three","Using too much sauce before baking and not reserving any to drizzle fresh at serving time, which mutes the bright garlic flavor","Refrigerating the containers while still warm, which creates condensation and makes the rice mushy over time"]', '["meal prep","honey garlic","chicken thighs","rice bowls","broccoli","high protein","weekly prep","Sunday cooking","batch cooking","glaze","asian-inspired","weekday lunches","fitness meals","low stress","sheet pan"]', '["high-protein","dairy-free-optional","gluten-free-optional"]', 'meal-prep', 'ai');
INSERT INTO recipes (title, slug, description, quick_summary, cuisine, difficulty, prep_time, cook_time, total_time, servings, calories, protein, carbs, fat, fiber, ingredients, steps, substitutions, common_mistakes, tags, dietary, category, source) VALUES ('PCOS-Friendly Low-Glycemic Berry Smoothie Bowl', 'pcos-friendly-low-glycemic-berry-smoothie-bowl', 'A vibrant, hormone-balancing smoothie bowl bursting with antioxidant-rich mixed berries, creamy avocado, and blood-sugar-stabilizing ingredients carefully chosen to support PCOS management. This nourishing bowl combines the power of low-glycemic fruits with healthy fats and plant-based protein to help regulate insulin levels and reduce inflammation — two critical factors for women managing polycystic ovary syndrome. Every spoonful delivers a gorgeous medley of flavors while keeping your hormones happy and your energy steady throughout the morning.', 'A creamy, low-glycemic berry smoothie bowl loaded with anti-inflammatory ingredients, healthy fats, and fiber to support hormone balance and insulin sensitivity for PCOS management.', 'American', 'Easy', 10, 0, 10, 1, 380, 18, 38, 18, 12, '[{"amount":"1","unit":"cup","item":"frozen mixed berries (blueberries, raspberries, blackberries)","group":"Smoothie Base"},{"amount":"0.5","unit":"medium","item":"ripe avocado, frozen","group":"Smoothie Base"},{"amount":"0.5","unit":"cup","item":"frozen cauliflower florets","group":"Smoothie Base"},{"amount":"1","unit":"scoop","item":"unflavored or vanilla pea protein powder (about 25g)","group":"Smoothie Base"},{"amount":"0.5","unit":"cup","item":"unsweetened almond milk","group":"Smoothie Base"},{"amount":"1","unit":"tablespoon","item":"ground flaxseed","group":"Smoothie Base"},{"amount":"1","unit":"teaspoon","item":"Ceylon cinnamon","group":"Smoothie Base"},{"amount":"0.5","unit":"teaspoon","item":"pure vanilla extract","group":"Smoothie Base"},{"amount":"0.25","unit":"cup","item":"fresh blueberries","group":"Toppings"},{"amount":"0.25","unit":"cup","item":"fresh raspberries","group":"Toppings"},{"amount":"2","unit":"tablespoons","item":"hemp seeds","group":"Toppings"},{"amount":"1","unit":"tablespoon","item":"raw pumpkin seeds (pepitas)","group":"Toppings"},{"amount":"1","unit":"tablespoon","item":"unsweetened coconut flakes","group":"Toppings"},{"amount":"1","unit":"teaspoon","item":"raw cacao nibs","group":"Toppings"},{"amount":"0.5","unit":"teaspoon","item":"bee pollen (optional)","group":"Toppings"},{"amount":"1","unit":"drizzle","item":"tahini (about 1 teaspoon)","group":"Toppings"}]', '[{"title":"Prep Your Frozen Ingredients","text":"Make sure your avocado and cauliflower are frozen solid — this is the secret to achieving that thick, spoonable smoothie bowl consistency without adding ice, which dilutes flavor. If your avocado is fresh, cube it and freeze for at least 2 beforehand. The cauliflower adds creaminess and volume with virtually no impact on blood sugar.","timer":0},{"title":"Add Ingredients to Blender","text":"Place the frozen mixed berries, frozen avocado, frozen cauliflower, pea protein powder, ground flaxseed, Ceylon cinnamon, and vanilla extract into a high-powered blender. Pour the unsweetened almond milk in last. Use the minimum liquid needed — you want a very thick consistency that holds your toppings proudly. Add liquid one tablespoon at a time if the blender struggles.","timer":0},{"title":"Blend Until Smooth","text":"Blend on high speed, using the tamper tool if your blender has one to push ingredients toward the blade. Blend for 30 to 45 seconds until completely smooth with no chunks remaining. Stop and scrape down the sides as needed. The mixture should be extremely thick — almost like soft-serve ice cream. If it seems too thin, add a tablespoon more frozen berries and blend briefly.","timer":45},{"title":"Pour Into a Chilled Bowl","text":"Pour or scoop the thick smoothie into a wide, chilled bowl. Use a spoon to smooth the surface and create an even canvas for your toppings. Working quickly keeps the smoothie cold and prevents it from melting before you add toppings.","timer":0},{"title":"Arrange Toppings Beautifully","text":"Working from one side to the other, arrange your toppings in sections or rows for a stunning presentation. Place the fresh blueberries and raspberries first, then sprinkle hemp seeds and pumpkin seeds for a protein and omega-3 boost. Add the coconut flakes and cacao nibs for crunch and antioxidants. Drizzle tahini lightly over the entire bowl for healthy fats that slow sugar absorption. Finish with bee pollen if using.","timer":0},{"title":"Serve Immediately","text":"Enjoy your smoothie bowl immediately while it is cold and thick. Eat it with intention — sitting down, without distractions — as mindful eating also supports hormonal health and digestion. Stir gently as you eat to incorporate the toppings into each spoonful.","timer":0}]', '[{"original":"pea protein powder","swap":"unflavored collagen peptides or plain Greek yogurt (if not dairy-free) for equal protein content"},{"original":"frozen cauliflower","swap":"frozen zucchini chunks — equally neutral in flavor and low in carbohydrates"},{"original":"unsweetened almond milk","swap":"unsweetened coconut milk or oat milk (note: oat milk is slightly higher glycemic)"},{"original":"frozen avocado","swap":"2 tablespoons full-fat coconut cream for similar creaminess and healthy fat content"},{"original":"hemp seeds","swap":"chia seeds — equally rich in omega-3 fatty acids and fiber"},{"original":"tahini drizzle","swap":"natural almond butter or sunflower seed butter for a different nutty flavor"},{"original":"Ceylon cinnamon","swap":"half the amount of cassia cinnamon — it is stronger in flavor but use Ceylon when possible for PCOS as it has better blood sugar benefits"}]', '["Adding too much liquid, which results in a runny smoothie you cannot eat with a spoon — always start with less liquid than you think you need","Using fresh instead of frozen avocado and cauliflower, which prevents the thick, creamy texture essential for a bowl-style smoothie","Sweetening with honey, agave, or dates thinking they are healthier — these still spike blood sugar and undermine the PCOS-friendly goal of this recipe","Skipping the protein powder or another protein source, which leads to faster blood sugar spikes from the fruit carbohydrates","Using flavored protein powders with artificial sweeteners or added sugars that can disrupt gut health and hormone balance","Blending for too long, which warms the ingredients from friction and creates a melted, soupy consistency","Forgetting to chill the bowl beforehand — a room-temperature bowl melts the smoothie quickly and ruins the eating experience","Skipping the healthy fat component like avocado or tahini — fat is essential for slowing glucose absorption and supporting hormone production"]', '["pcos","smoothie bowl","low glycemic","hormone balance","anti-inflammatory","insulin resistance","berry","high protein","high fiber","no added sugar","meal prep","breakfast","dairy-free","plant-based protein","women''s health","gut health"]', '["pcos-friendly","gluten-free","dairy-free","refined-sugar-free","low-glycemic","high-fiber","high-protein"]', 'pcos', 'ai');
INSERT INTO recipes (title, slug, description, quick_summary, cuisine, difficulty, prep_time, cook_time, total_time, servings, calories, protein, carbs, fat, fiber, ingredients, steps, substitutions, common_mistakes, tags, dietary, category, source) VALUES ('Iron-Rich Spinach and Lentil Dal', 'iron-rich-spinach-lentil-dal-pregnancy', 'A nourishing and deeply satisfying dal crafted specifically for expectant mothers, this vibrant dish combines the powerhouse duo of red lentils and fresh spinach to deliver an impressive boost of plant-based iron in every spoonful. Fragrant cumin, turmeric, and coriander bloom in warm oil to create an aromatic base that transforms simple pantry staples into a comforting meal that feels like a hug from the inside. The addition of vitamin C-rich tomatoes alongside the iron-dense ingredients is intentional — ascorbic acid significantly enhances non-heme iron absorption, making this dal as nutritionally strategic as it is delicious. Finished with a squeeze of fresh lemon and a handful of wilted baby spinach, this golden, creamy dal is gentle on a sensitive pregnancy palate while delivering the folate, protein, and iron that growing bodies truly need.', 'A creamy, golden red lentil and spinach dal loaded with pregnancy-essential iron, folate, and protein. Aromatic spices, vitamin C-rich tomatoes, and a bright lemon finish make this comforting bowl as nourishing as it is delicious.', 'Indian', 'Easy', 15, 35, 50, 4, 310, 18, 48, 7, 14, '[{"amount":"1.5","unit":"cups","item":"red lentils, rinsed thoroughly","group":"Dal Base"},{"amount":"4","unit":"cups","item":"low-sodium vegetable broth","group":"Dal Base"},{"amount":"1","unit":"cup","item":"water","group":"Dal Base"},{"amount":"5","unit":"oz","item":"fresh baby spinach, roughly chopped","group":"Dal Base"},{"amount":"2","unit":"tablespoons","item":"cold-pressed coconut oil or light olive oil","group":"Tempering"},{"amount":"1","unit":"teaspoon","item":"cumin seeds","group":"Tempering"},{"amount":"1","unit":"medium","item":"yellow onion, finely diced","group":"Aromatics"},{"amount":"4","unit":"cloves","item":"garlic, minced","group":"Aromatics"},{"amount":"1","unit":"tablespoon","item":"fresh ginger, grated","group":"Aromatics"},{"amount":"2","unit":"medium","item":"ripe tomatoes, finely chopped","group":"Aromatics"},{"amount":"1","unit":"teaspoon","item":"ground turmeric","group":"Spices"},{"amount":"1.5","unit":"teaspoons","item":"ground coriander","group":"Spices"},{"amount":"1","unit":"teaspoon","item":"ground cumin","group":"Spices"},{"amount":"0.5","unit":"teaspoon","item":"garam masala","group":"Spices"},{"amount":"0.25","unit":"teaspoon","item":"black pepper, freshly ground","group":"Spices"},{"amount":"1","unit":"teaspoon","item":"fine sea salt, or to taste","group":"Seasoning"},{"amount":"1","unit":"whole","item":"lemon, juiced (about 3 tablespoons)","group":"Seasoning"},{"amount":"2","unit":"tablespoons","item":"fresh cilantro, chopped, for garnish","group":"Garnish"},{"amount":"1","unit":"tablespoon","item":"pumpkin seeds, toasted, for garnish","group":"Garnish"}]', '[{"title":"Rinse and Prep the Lentils","text":"Place the red lentils in a fine-mesh sieve and rinse under cold running water, stirring with your fingers, until the water runs completely clear. This removes excess starch and any debris. Set aside to drain. While the lentils drain, prepare all your vegetables — dice the onion, mince the garlic, grate the ginger, and chop the tomatoes. Having everything ready before you start cooking ensures a smooth, stress-free process.","timer":0},{"title":"Bloom the Cumin Seeds","text":"Heat the coconut oil or olive oil in a large heavy-bottomed pot or Dutch oven over medium heat. Once the oil is shimmering and hot, add the cumin seeds. Let them sizzle and pop for about 45 to 60 seconds, stirring occasionally, until they turn a shade darker and release their warm, nutty fragrance. This tempering step is crucial — it unlocks the deep, complex flavors of the spice and infuses the entire oil base with aromatic goodness.","timer":60},{"title":"Sauté the Aromatics","text":"Add the diced onion to the bloomed cumin oil and cook, stirring frequently, for 7 to 8 until the onion becomes soft, translucent, and lightly golden at the edges. Reduce heat slightly if needed to avoid burning. Add the minced garlic and grated ginger and stir continuously for another 2 until fragrant and the raw smell disappears completely. The kitchen should smell wonderfully warm and inviting at this stage.","timer":600},{"title":"Build the Spice Base","text":"Add the ground turmeric, coriander, cumin, garam masala, and black pepper directly to the onion mixture. Stir vigorously and cook the spices for 1 to 2, allowing them to toast gently in the oil and coat the aromatics completely. If the mixture looks a little dry, add a small splash of vegetable broth to prevent scorching. Add the chopped tomatoes and cook for 5 to 6, mashing them occasionally with the back of a spoon, until they break down completely and form a thick, jammy paste with the spices.","timer":480},{"title":"Cook the Lentils","text":"Add the rinsed red lentils to the pot and stir well to coat them evenly in the tomato-spice base. Pour in the vegetable broth and water, stirring to combine. Increase the heat to medium-high and bring the mixture to a boil. Once boiling, reduce the heat to medium-low, partially cover the pot with a lid, and simmer for 20 to 25, stirring occasionally, until the lentils are completely soft and have broken down into a thick, creamy, porridge-like consistency. Add a splash more water if the dal becomes too thick before the lentils are fully cooked.","timer":1500},{"title":"Wilt in the Spinach","text":"Once the lentils are fully cooked and creamy, add all the chopped baby spinach to the pot in two or three large handfuls, stirring gently between each addition to help it wilt. Cook for 3 to 4 over medium heat, stirring continuously, until all the spinach is fully wilted, deeply green, and incorporated into the golden dal. The vibrant green against the golden lentils signals that the iron-rich nutrients are perfectly preserved — avoid overcooking the spinach beyond this point.","timer":240},{"title":"Season and Finish with Lemon","text":"Remove the pot from heat. Add the sea salt and squeeze in all the fresh lemon juice, stirring well to combine. Taste the dal and adjust salt or lemon as needed — the lemon is not just for flavor but critically enhances the absorption of plant-based iron from the lentils and spinach, so do not skip this step. Let the dal rest for 2 to 3 off the heat before serving to allow the flavors to meld together beautifully.","timer":180},{"title":"Serve and Garnish","text":"Ladle the hot dal into warm bowls. Garnish generously with fresh chopped cilantro and a sprinkle of toasted pumpkin seeds for an extra boost of zinc and magnesium. Serve alongside warm whole-grain flatbread, brown rice, or simply enjoy on its own. For maximum iron absorption, pair this meal with a small glass of orange juice or vitamin C-rich fruit on the side.","timer":0}]', '[{"original":"Red lentils","swap":"Green or brown lentils work well but require an additional 15 to 20 of cooking time and will produce a heartier, less creamy texture"},{"original":"Fresh baby spinach","swap":"Frozen spinach (thawed and squeezed dry) is an equally nutritious and convenient option — use 6 oz frozen in place of fresh"},{"original":"Fresh tomatoes","swap":"One 14-oz can of diced tomatoes (no added salt) makes a great substitute and intensifies the base flavor slightly"},{"original":"Coconut oil","swap":"Ghee can be used if you are not strictly vegan; it adds a rich, buttery depth to the tempering"},{"original":"Fresh lemon juice","swap":"Fresh lime juice works equally well and adds a slightly more citrusy brightness to the finished dal"},{"original":"Vegetable broth","swap":"Plain water works as a substitute, though broth adds a richer depth of flavor to the finished dish"},{"original":"Pumpkin seeds","swap":"Hemp seeds or sesame seeds are equally nutritious iron-rich garnish alternatives"}]', '["Skipping the lentil rinse — unwashed lentils produce a gummy, starchy dal and can cause excess bloating, which is particularly uncomfortable during pregnancy","Not blooming the spices long enough — rushing the tempering step results in a flat, one-dimensional flavor that lacks the warmth and depth this dal deserves","Omitting the lemon juice — the vitamin C in lemon is scientifically proven to enhance non-heme iron absorption from plant sources by up to three times, so this step is nutritionally essential, not optional","Overcooking the spinach — adding spinach too early or cooking it for too long destroys heat-sensitive folate, a critical nutrient for fetal neural tube development","Adding all the spinach at once — adding it in batches ensures even wilting and prevents the pot from cooling too dramatically or the spinach clumping together","Cooking on too high a heat after adding lentils — a rapid boil can cause the lentils to cook unevenly on the outside while remaining hard in the center; a gentle simmer is key","Not stirring the dal frequently enough during the lentil cooking phase — red lentils are starchy and will stick and scorch on the bottom of the pot if left unattended","Using unpasteurized spices from an uncertain source during pregnancy — always use fresh, commercially sealed spices to avoid any risk of contamination"]', '["pregnancy","iron-rich","lentil","dal","spinach","vegan","folate","prenatal nutrition","Indian-inspired","one-pot","high-protein","high-fiber","comforting","meal prep","healthy"]', '["pregnancy-safe","vegan","vegetarian","dairy-free","gluten-free","nut-free","high-iron","high-folate","high-fiber","high-protein"]', 'pregnancy', 'ai');
INSERT INTO recipes (title, slug, description, quick_summary, cuisine, difficulty, prep_time, cook_time, total_time, servings, calories, protein, carbs, fat, fiber, ingredients, steps, substitutions, common_mistakes, tags, dietary, category, source) VALUES ('Lemon Herb Crusted Baked Cod', 'lemon-herb-crusted-baked-cod', 'A beautifully light yet satisfying baked cod crowned with a golden, fragrant crust of lemon zest, fresh herbs, and whole grain breadcrumbs. This elegant dish delivers clean, bright flavors while keeping your heart happy with omega-rich fish and heart-protective olive oil. The crust locks in moisture while creating an irresistible texture contrast that makes every bite a delight.', 'Golden herb-crusted cod baked to flaky perfection with lemon, garlic, and fresh parsley — a 30-minute heart-healthy dinner that feels indulgent without the guilt.', 'Mediterranean', 'Easy', 10, 18, 28, 4, 285, 38, 12, 9, 1, '[{"amount":"4","unit":"fillets (6 oz each)","item":"fresh cod fillets","group":"Fish"},{"amount":"2","unit":"tablespoons","item":"extra virgin olive oil","group":"Fish"},{"amount":"1","unit":"teaspoon","item":"kosher salt","group":"Fish"},{"amount":"0.5","unit":"teaspoon","item":"freshly ground black pepper","group":"Fish"},{"amount":"0.5","unit":"cup","item":"whole wheat panko breadcrumbs","group":"Herb Crust"},{"amount":"3","unit":"tablespoons","item":"fresh flat-leaf parsley, finely chopped","group":"Herb Crust"},{"amount":"2","unit":"tablespoons","item":"fresh dill, finely chopped","group":"Herb Crust"},{"amount":"1","unit":"tablespoon","item":"fresh chives, finely chopped","group":"Herb Crust"},{"amount":"3","unit":"cloves","item":"garlic, minced","group":"Herb Crust"},{"amount":"2","unit":"teaspoons","item":"lemon zest (from 1 large lemon)","group":"Herb Crust"},{"amount":"2","unit":"tablespoons","item":"fresh lemon juice","group":"Herb Crust"},{"amount":"1","unit":"tablespoon","item":"extra virgin olive oil","group":"Herb Crust"},{"amount":"0.25","unit":"teaspoon","item":"red pepper flakes","group":"Herb Crust"},{"amount":"1","unit":"whole","item":"lemon, sliced into rounds","group":"For Serving"},{"amount":"4","unit":"sprigs","item":"fresh parsley","group":"For Serving"}]', '[{"title":"Preheat Oven","text":"Preheat your oven to 400°F (200°C). Line a rimmed baking sheet with parchment paper and lightly brush it with a small amount of olive oil to prevent sticking.","timer":0},{"title":"Prepare the Herb Crust Mixture","text":"In a medium bowl, combine the whole wheat panko breadcrumbs, chopped parsley, dill, chives, minced garlic, lemon zest, lemon juice, 1 tablespoon olive oil, and red pepper flakes. Mix thoroughly with a fork until the breadcrumbs are evenly moistened and the herbs are well distributed. The mixture should hold together slightly when pressed.","timer":0},{"title":"Season the Cod","text":"Pat the cod fillets completely dry with paper towels — this is crucial for a good crust to adhere. Place them on the prepared baking sheet. Drizzle the 2 tablespoons of olive oil evenly over the top of each fillet, then season generously with kosher salt and black pepper.","timer":0},{"title":"Apply the Herb Crust","text":"Divide the herb breadcrumb mixture evenly among the four fillets, pressing it firmly and gently onto the top surface of each piece of cod. Use your fingers to create an even layer about a quarter-inch thick across the entire top of each fillet. Press gently to ensure the crust adheres well.","timer":0},{"title":"Bake to Perfection","text":"Transfer the baking sheet to the preheated oven and bake for 15 to 18, depending on the thickness of your fillets. The cod is done when the crust is golden brown and crispy and the fish flakes easily when tested with a fork at its thickest point. An internal temperature of 145°F confirms it is perfectly cooked.","timer":1080},{"title":"Rest and Serve","text":"Remove from the oven and let the fish rest for 2 before serving. This allows the juices to redistribute. Plate each fillet and garnish with fresh lemon rounds and a sprig of parsley. Serve immediately while the crust is at its crispiest.","timer":120}]', '[{"original":"cod fillets","swap":"haddock, tilapia, halibut, or pollock work beautifully with the same technique"},{"original":"whole wheat panko breadcrumbs","swap":"almond flour or crushed walnuts for a gluten-free, even more heart-healthy crust"},{"original":"fresh dill","swap":"fresh tarragon or basil for a different but equally delicious herbal profile"},{"original":"fresh parsley","swap":"fresh cilantro for a brighter, more citrusy herbaceous note"},{"original":"red pepper flakes","swap":"smoked paprika for a gentle warmth without the heat"}]', '["Not patting the cod fillets dry before adding the crust — moisture prevents the crust from becoming golden and crispy","Overcooking the cod, which causes it to become rubbery and dry; always check at the 15-minute mark","Pressing the crust on too loosely — a firm, even press ensures it stays intact during baking","Using stale or old breadcrumbs, which will produce a dull, dense crust instead of a light golden one","Skipping the resting period after baking, which causes the fish to fall apart when plating","Using bottled lemon juice instead of fresh — the bright zest and fresh juice are essential to the flavor of this dish"]', '["baked cod","lemon herb","heart-healthy","omega-3","weeknight dinner","Mediterranean","low-calorie","high-protein","gluten-adaptable","quick dinner","clean eating","light and healthy"]', '["heart-healthy","high-protein","low-fat","low-sodium","dairy-free","pescatarian"]', 'heart-healthy', 'ai');
INSERT INTO recipes (title, slug, description, quick_summary, cuisine, difficulty, prep_time, cook_time, total_time, servings, calories, protein, carbs, fat, fiber, ingredients, steps, substitutions, common_mistakes, tags, dietary, category, source) VALUES ('Exam Week Salmon Avocado Poke Bowl', 'exam-week-salmon-avocado-poke-bowl', 'A vibrant, nourishing poke bowl packed with omega-3-rich salmon, creamy avocado, and wholesome toppings designed to fuel your brain through the most intense study sessions. Fresh, colorful, and incredibly satisfying, this bowl delivers sustained energy without the post-meal crash that can derail your focus.', 'A power-packed poke bowl with silky sashimi-grade salmon, buttery avocado, and a umami-rich sesame soy marinade served over fluffy sushi rice with crunchy toppings for the ultimate brain-boosting meal.', 'Hawaiian-Japanese Fusion', 'Easy', 20, 30, 50, 2, 620, 42, 58, 24, 9, '[{"amount":"300","unit":"g","item":"sashimi-grade salmon, cut into 1-inch cubes","group":"Salmon Marinade"},{"amount":"3","unit":"tbsp","item":"gluten-free tamari sauce","group":"Salmon Marinade"},{"amount":"1","unit":"tbsp","item":"toasted sesame oil","group":"Salmon Marinade"},{"amount":"1","unit":"tsp","item":"fresh ginger, finely grated","group":"Salmon Marinade"},{"amount":"1","unit":"tsp","item":"honey","group":"Salmon Marinade"},{"amount":"1","unit":"tsp","item":"rice vinegar","group":"Salmon Marinade"},{"amount":"1","unit":"tsp","item":"sriracha","group":"Salmon Marinade"},{"amount":"2","unit":"cups","item":"sushi rice, uncooked","group":"Sushi Rice"},{"amount":"2.5","unit":"cups","item":"water","group":"Sushi Rice"},{"amount":"2","unit":"tbsp","item":"rice vinegar","group":"Sushi Rice"},{"amount":"1","unit":"tbsp","item":"sugar","group":"Sushi Rice"},{"amount":"1","unit":"tsp","item":"salt","group":"Sushi Rice"},{"amount":"1","unit":"large","item":"ripe avocado, sliced","group":"Bowl Toppings"},{"amount":"1","unit":"cup","item":"edamame, shelled and cooked","group":"Bowl Toppings"},{"amount":"1","unit":"cup","item":"cucumber, thinly sliced into half-moons","group":"Bowl Toppings"},{"amount":"1","unit":"cup","item":"shredded purple cabbage","group":"Bowl Toppings"},{"amount":"2","unit":"tbsp","item":"pickled ginger","group":"Bowl Toppings"},{"amount":"2","unit":"tbsp","item":"toasted sesame seeds","group":"Bowl Toppings"},{"amount":"3","unit":"stalks","item":"green onions, thinly sliced","group":"Bowl Toppings"},{"amount":"1","unit":"sheet","item":"nori, cut into thin strips","group":"Bowl Toppings"},{"amount":"3","unit":"tbsp","item":"Japanese mayonnaise (Kewpie)","group":"Spicy Mayo Drizzle"},{"amount":"1","unit":"tbsp","item":"sriracha","group":"Spicy Mayo Drizzle"},{"amount":"1","unit":"tsp","item":"toasted sesame oil","group":"Spicy Mayo Drizzle"},{"amount":"1","unit":"tsp","item":"fresh lime juice","group":"Spicy Mayo Drizzle"}]', '[{"title":"Cook the Sushi Rice","text":"Rinse the sushi rice under cold water until the water runs clear, about 3 to 4 rinses. This removes excess starch and prevents gummy rice. Combine the rinsed rice and water in a medium saucepan. Bring to a boil over high heat, then reduce to the lowest possible simmer, cover tightly, and cook for 18. Remove from heat and let steam, still covered, for 10. Do not lift the lid during cooking.","timer":1680},{"title":"Season the Rice","text":"While the rice rests, combine rice vinegar, sugar, and salt in a small bowl and microwave for 20 seconds, stirring until sugar and salt are fully dissolved. Transfer the cooked rice to a large wooden or glass bowl. Using a rice paddle or spatula, gently fold the vinegar mixture into the hot rice using a slicing motion rather than stirring. Fan the rice as you fold to help it cool and develop a subtle sheen. Allow to cool to room temperature.","timer":600},{"title":"Marinate the Salmon","text":"Ensure your salmon is sashimi-grade and very cold. Cut into uniform 1-inch cubes for even marination. In a medium bowl, whisk together gluten-free tamari, sesame oil, fresh grated ginger, honey, rice vinegar, and sriracha until well combined. Add the salmon cubes and gently toss to coat every piece evenly. Cover with plastic wrap and refrigerate for exactly 15 — no longer, as the acid can begin to break down the delicate fish texture.","timer":900},{"title":"Prepare the Spicy Mayo","text":"In a small bowl, whisk together Japanese mayonnaise, sriracha, toasted sesame oil, and fresh lime juice until smooth and fully combined. Taste and adjust the sriracha level to your heat preference. Transfer to a squeeze bottle or a small zip-lock bag with one corner snipped for easy drizzling. Set aside at room temperature.","timer":120},{"title":"Prep All the Toppings","text":"While the salmon marinates, prepare all bowl toppings. Halve, pit, and slice the avocado, keeping slices thick to prevent bruising. Slice the cucumber into thin half-moons. Shred the purple cabbage finely. Cook the edamame if using frozen — simply microwave with a splash of water for 2. Slice the green onions on a diagonal for a prettier presentation. Cut nori sheets into thin 2-inch strips using scissors. Toast sesame seeds in a dry pan over medium heat for 2 until golden and fragrant.","timer":300},{"title":"Assemble the Bowls","text":"Divide the seasoned sushi rice evenly between two wide bowls, filling each about halfway. Arrange toppings in distinct sections around the rice: place avocado slices fanning out on one side, cucumber half-moons beside them, a mound of shredded purple cabbage, and a generous pile of edamame. Place the marinated salmon cubes prominently in the center of each bowl. Tuck pickled ginger along one edge and scatter nori strips across the top.","timer":180},{"title":"Garnish and Serve","text":"Drizzle the spicy mayo generously over the salmon and across the entire bowl in a zigzag pattern. Sprinkle toasted sesame seeds liberally over everything. Finish with sliced green onions scattered on top. Serve immediately for the freshest flavor and best texture. If meal prepping, keep the salmon, rice, and toppings stored separately and assemble just before eating.","timer":60}]', '[{"original":"sashimi-grade salmon","swap":"sashimi-grade tuna, cooked shrimp, or marinated tofu cubes for a vegan option"},{"original":"sushi rice","swap":"cauliflower rice for a low-carb version or brown rice for extra fiber"},{"original":"gluten-free tamari","swap":"coconut aminos for a soy-free and lower-sodium alternative"},{"original":"Japanese mayonnaise","swap":"regular mayonnaise mixed with a tiny drop of rice vinegar and a pinch of sugar"},{"original":"edamame","swap":"frozen peas or steamed broccoli florets"},{"original":"honey","swap":"maple syrup or agave nectar for a vegan-friendly marinade"}]', '["Using non-sashimi-grade salmon — always confirm with your fishmonger that the salmon is safe for raw consumption","Over-marinating the salmon for longer than 20, which causes the fish to become mushy and lose its silky texture","Skipping the rinse on sushi rice, resulting in an overly starchy and clumped final product","Lifting the rice pot lid during cooking, which releases steam and prevents proper cooking","Adding the vinegar seasoning to hot steaming rice in the pot instead of transferring to a bowl first, which makes it gummy","Cutting the avocado too far in advance without an acid coating, causing it to brown quickly","Using regular soy sauce instead of tamari, which contains gluten and breaks the dietary requirement","Not patting the salmon dry before marinating, which dilutes the flavor of the marinade"]', '["poke bowl","salmon","avocado","brain food","exam week","omega-3","sushi rice","Hawaiian","Japanese","meal prep","healthy","fresh","no-cook protein","study snack","focus food","high protein","gluten free","bowl meal","quick assembly","weeknight dinner"]', '["high-protein","gluten-free"]', 'brain-food', 'ai');
